// ── Daily Challenge Question Bank ────────────────────────────────────────────
// Scenario-based questions, separate from the topic question banks.
// The daily seeded shuffle picks 10 from this pool each day.

export const DAILY_QUESTIONS = {
  he: [
    // ── Workloads ──
    {q:"ה-Pod בשם api-server מציג סטטוס CrashLoopBackOff. מה הצעד הראשון לאבחון?",options:["kubectl delete pod api-server","kubectl logs api-server --previous","kubectl edit pod api-server","kubectl drain node"],answer:1,explanation:"-previous מציג לוגים מהריצה שקרסה.\nזה תמיד הצעד הראשון כשיש CrashLoopBackOff – הלוגים יחשפו את שגיאת האתחול."},
    {q:"ה-Pod נשאר Pending. kubectl describe מציג: '0/3 nodes available: 3 Insufficient memory'. מה הפתרון הנכון?",options:["הפעלת Pod מחדש","שינוי namespace","הורדת memory requests של ה-Pod או הוספת Node","מחיקת Pods אחרים"],answer:2,explanation:"ה-Scheduler לא מוצא Node עם זיכרון פנוי שיכסה את ה-requests.\nיש להוריד את דרישות הזיכרון של ה-Pod או להוסיף Node לאשכול."},
    {q:"תהליך Rolling update של Deployment נתקע – Pod חדש נוצר אבל לא עולה לReady. מה הסיבה הנפוצה ביותר?",options:["image לא קיים בrepo","readiness probe נכשלת על ה-Pod החדש","אין DNS","RBAC חסר"],answer:1,explanation:"כשrollout נתקע, הסיבה הנפוצה ביותר היא readiness probe כושלת – Kubernetes מחכה לPod להיות Ready לפני שממשיך לעדכן Pods נוספים."},
    {q:"ה-Pod קרס עם OOMKilled. מה המשמעות ומה הצעד הבא?",options:["בעיית רשת – בודקים NetworkPolicy","הקרנל סיים את הקונטיינר כי חרג מmemory limit – מגדילים limits.memory","image פגום – מושכים מחדש","CPU throttling – מגדילים CPU"],answer:1,explanation:"OOMKilled = Out Of Memory Killed.\nהקרנל הרג את הקונטיינר מאחר חרג ממגבלת הזיכרון.\nיש להגדיל את limits.memory או לאתר memory leak באפליקציה."},
    {q:"ה-HPA מוגדר ל-Deployment, אך לא מבצע scale למרות עומס CPU גבוה. מה הסיבה הסבירה ביותר?",options:["אין Ingress","metrics-server לא מותקן או לא עובד","maxReplicas נמוך מדי","namespace שגוי"],answer:1,explanation:"HPA תלוי ב-metrics-server כדי לקרוא נתוני CPU/memory.\nללא metrics-server, ה-HPA לא יכול לקבל מדדים ולכן לא מבצע scaling."},
    {q:"ה-Init Container נכשל בכל ניסיון עם exit code 1. הLogs מציגים 'connection refused'. מה בודקים?",options:["resource limits של ה-init container","האם השירות שה-init container מחכה לו בכלל פעיל","image tag שגוי","namespace שגוי"],answer:1,explanation:"Init containers משמשים לרוב להמתנה לשירות חיצוני. connection refused אומר שהיעד לא זמין.\nיש לוודא שה-dependency כבר רץ ופועל."},
    {q:"ה-Deployment מנסה להריץ 5 replicas אך רק 3 עולים. kubectl describe מציג 'pod didn't trigger scale-up'. מה בודקים?",options:["cluster autoscaler לא מוגדר או Nodes לא יכולים להתרחב","image שגוי","secrets חסרים","namespace quota"],answer:0,explanation:"כש-Pods לא יכולים להיות scheduled, Cluster Autoscaler אמור להוסיף Nodes.\nאם זה לא קורה – ייתכן שאין תצורת autoscaling, הgit quota ממלאה, או שאין cloud instances זמינות."},
    {q:"ה-Job רץ אך לעולם לא מסתיים. kubectl get job מציג COMPLETIONS 0/1 כבר שעה. מה בודקים?",options:["מחיקת ה-Job ויצירה מחדש","kubectl logs של Pod ה-Job – ייתכן שהתהליך תקוע","kubectl describe node","שינוי restartPolicy"],answer:1,explanation:"Job שלא מסתיים בד\"כ תקוע בתהליך שלא יוצא. יש לראות לוגים של ה-Pod כדי להבין אם זה deadlock, קלט חסר, או תהליך אינסופי."},
    {q:"ה-Pod מציג READY 0/1 אך STATUS Running. הAפליקציה בפנים עובדת. מה הבעיה?",options:["liveness probe נכשלת","readiness probe נכשלת – הPod לא מקבל traffic","image שגוי","resource limits נמוכים"],answer:1,explanation:"0/1 Ready אומר שreadiness probe נכשלת.\nה-Pod רץ אבל לא יקבל traffic מה-Service.\nיש לבדוק את הגדרת ה-readiness probe ולוודא שהPath/Port נכונים."},
    {q:"ה-StatefulSet database-0 קרס ולא עולה מחדש. kubectl describe מציג 'volume is already exclusively attached'. מה קרה?",options:["image חסר","ה-PVC עם ReadWriteOnce מחובר ל-Node אחר – Node drain לא הושלם","namespace שגוי","RBAC חסר"],answer:1,explanation:"ReadWriteOnce מאפשר חיבור לNode אחד בלבד.\nאם ה-Node הקודם לא שחרר את ה-volume לחלוטין (למשל לאחר crash), ה-Pod החדש לא יכול לחבר אותו.\nפתרון: לחכות לNode detach או לאלץ detach."},

    // ── Networking ──
    {q:"הפקודה kubectl get endpoints my-svc מציג '<none>'. Service קיים, Pods רצים. מה הבעיה?",options:["חסר Ingress","selector של Service לא תואם labels של Pods","חסר NodePort","חסר NetworkPolicy"],answer:1,explanation:"כשEndpoints ריק, זה כמעט תמיד חוסר התאמה בין selector של ה-Service לבין labels של ה-Pods.\nבודקים עם kubectl get pods --show-labels."},
    {q:"ה-Pod לא מצליח לפנות לשירות אחר באשכול. curl http://my-svc.default.svc.cluster.local מחזיר 'Could not resolve host'. מה בודקים?",options:["NetworkPolicy","CoreDNS Pods בkube-system – האם הם רצים ובריאים","Ingress","service type"],answer:1,explanation:"שגיאת DNS בתוך האשכול מצביעה על CoreDNS.\nיש לבדוק: kubectl get pods -n kube-system | grep coredns ולוודא שהם Running ו-Ready."},
    {q:"ה-Ingress מוגדר, DNS מצביע נכון, אך כל הבקשות מחזירות 404. מה בודקים?",options:["TLS cert","path ב-Ingress rule לא תואם ל-path שהאפליקציה מאזינה לו","namespace של Ingress","image של Pod"],answer:1,explanation:"404 מ-Ingress בד\"כ אומר שה-path rule לא תואם. אם האפליקציה מאזינה על / אבל ה-Ingress מגדיר path: /api, הנתיב לא יתאים. יש לבדוק path ו-pathType."},
    {q:"כלל ה-NetworkPolicy הוחלה על namespace. עכשיו Pod A לא יכול לדבר עם Pod B באותו namespace. מה קרה?",options:["NetworkPolicy ב-K8s default-deny – לא הוגדרה allow rule בין הPods","Pods בnamespaces שונים","Service לא קיים","DNS כשל"],answer:0,explanation:"NetworkPolicy ב-Kubernetes היא additive allow-list.\nכשמחילים policy, כל traffic שלא מוגדר במפורש כ-allow נחסם.\nיש להוסיף ingress rule שמאפשרת תקשורת בתוך ה-namespace."},
    {q:"ה-Service מסוג LoadBalancer נשאר בסטטוס Pending (EXTERNAL-IP <pending>) בsingle-node local cluster. מה הסיבה?",options:["חסר Ingress","LoadBalancer דורש cloud provider עם integration – ב-local cluster אין זה","חסר DNS","חסר TLS"],answer:1,explanation:"ServiceType LoadBalancer מסתמך על cloud provider (AWS, GCP, Azure) שיקצה IP חיצוני.\nב-local cluster (minikube, kind) זה לא זמין ללא כלים כמו MetalLB.\nלשימוש local משתמשים ב-NodePort."},
    {q:"ה-Pod לא יכול לגשת לאינטרנט. curl google.com נכשל, אבל Pod אחר באותו namespace כן מצליח. מה בודקים?",options:["kubectl logs","NetworkPolicy על ה-Pod הספציפי שחוסמת egress","image שגוי","DNS"],answer:1,explanation:"אם Pod אחד לא יכול לגשת לחוץ אבל אחרים כן, NetworkPolicy egress היא החשודה הראשית.\nיש לבדוק policies שחלות על ה-Pod לפי labels."},
    {q:"ה-Service ClusterIP נגיש מתוך הPods, אך NodePort על port 30080 לא נגיש מחוץ לאשכול. מה הסיבה האפשרית?",options:["firewall/security group חוסמים port 30080","חסר Ingress","DNS שגוי","RBAC"],answer:0,explanation:"NodePort פותח port על כל ה-Nodes, אך firewall חיצוני (security groups, iptables) עלול לחסום אותו.\nיש לוודא שport 30080 פתוח ב-security group ושאין iptables rule שחוסמת."},

    // ── Config & Security ──
    {q:"ה-Pod לא מצליח לפנות ל-Secrets שיצרת. kubectl describe pod מציג 'secret not found'. מה בודקים?",options:["RBAC","האם ה-Secret נמצא באותו namespace כמו ה-Pod","הצפנה של ה-Secret","image pull"],answer:1,explanation:"Secrets ו-Pods חייבים להיות באותו namespace.\nSecret בnamespace A לא נגיש ל-Pod בnamespace B.\nיש לוודא שהSecret נוצר בnamespace הנכון."},
    {q:"ה-ServiceAccount של Pod מנסה לבצע kubectl get pods ומקבל 'Forbidden'. Role קיים. מה חסר?",options:["הגדלת resource limits","RoleBinding שמחבר את ה-Role ל-ServiceAccount","ClusterRole","Secret"],answer:1,explanation:"Role לבד לא מספיקה.\nיש צורך ב-RoleBinding שמחבר בין ה-Role (הרשאות) לבין ה-Subject (ServiceAccount).\nללא RoleBinding, ה-Role לא תקפה."},
    {q:"ה-ConfigMap עודכן עם ערכים חדשים, אך האפליקציה ב-Pod עדיין רואה ערכים ישנים. למה?",options:["ConfigMap לא תקין","רוב האפליקציות טוענות ConfigMap פעם אחת בהפעלה – Pod צריך restart","RBAC חסם את ה-ConfigMap","namespace שגוי"],answer:1,explanation:"כשConfigMap מוגדר כ-env vars, השינויים יכנסו לתוקף רק אחרי restart של ה-Pod.\nאם מוגדר כvolume, עדכון יכול להגיע בתוך כמה דקות – אבל האפליקציה עצמה צריכה לקרוא מחדש."},
    {q:"ה-Pod מנסה לפנות ל-private Docker registry ומקבל 'ImagePullBackOff'. מה חסר?",options:["resource limits","imagePullSecrets לא מוגדר ב-Pod spec – חסר Secret עם credentials ל-registry","NetworkPolicy","Node taints"],answer:1,explanation:"כדי למשוך image מ-private registry, ה-Pod צריך imagePullSecrets שמפנה ל-Secret מסוג kubernetes.io/dockerconfigjson עם credentials של ה-registry."},
    {q:"ה-Pod מנסה לרוץ כ-root (uid 0) אבל נדחה. מה הסיבה הסבירה?",options:["חסר NetworkPolicy","PodSecurityAdmission או PodSecurityPolicy מגדיר runAsNonRoot: true","חסר PVC","חסר Service"],answer:1,explanation:"PodSecurity admission control יכול לאסור הרצה כroot.\nאם namespace מוגדר עם policy restricted או baseline, Pods שמנסים לרוץ כroot יידחו.\nיש לשנות securityContext.runAsUser."},
    {q:"ה-Secret מוגדר ב-Pod כenv var: value = 'dXNlcjpwYXNz'. האפליקציה מקבלת את הסטרינג הזה, לא את 'user:pass'. מה הבעיה?",options:["Secret מסוג שגוי","Secret נשמר ב-base64 אך K8s מפענח אוטומטית – אם האפליקציה מקבלת base64, נוצר Secret עם ערך שכבר encoded פעמיים","RBAC","namespace שגוי"],answer:1,explanation:"K8s מפענח Secret מbase64 אוטומטית כשמזריק לPod.\nאם נוצר Secret עם ערך שכבר base64 encoded, ה-Pod יקבל base64 במקום הערך האמיתי.\nיש ליצור Secret עם הערך הגולמי."},

    // ── Storage ──
    {q:"ה-PVC בסטטוס Pending. kubectl describe pvc מציג 'storageclass.storage.k8s.io not found'. מה הבעיה?",options:["חסר Namespace","StorageClass שצוין ב-PVC לא קיים באשכול – בדוק עם kubectl get storageclass","PV מלא","Secret חסר"],answer:1,explanation:"PVC מפנה ל-StorageClass שלא קיים.\nיש לוודא ששם ה-StorageClass ב-PVC תואם לאחד מה-StorageClasses הקיימים (kubectl get storageclass)."},
    {q:"שני Pods מנסים לחבר אותו PVC. ה-Pod השני נשאר Pending עם 'Multi-Attach error'. מה הסיבה?",options:["חסר NetworkPolicy","PVC עם accessMode ReadWriteOnce (RWO) יכול להיות מחובר לNode אחד בלבד","חסר Secret","Resource limits"],answer:1,explanation:"ReadWriteOnce אומר שהvolume יכול להיות mounted ל-Node אחד בלבד בכל זמן נתון.\nאם שני Pods על Nodes שונים מנסים לחבר, ה-Pod השני נחסם.\nפתרון: שינוי ל-ReadWriteMany אם ה-storage backend תומך."},
    {q:"פקודת Helm upgrade נכשל עם 'cannot patch because a resource with that name already exists (not managed by Helm)'. מה קרה?",options:["values.yaml שגוי","משאב נוצר ידנית מחוץ ל-Helm ולכן Helm לא מנהל אותו – משתמשים ב-helm upgrade --force או מוחקים ידנית","namespace שגוי","image שגוי"],answer:1,explanation:"Helm עוקב אחרי משאבים שהוא יצר.\nאם משאב נוצר ידנית עם אותו שם, Helm לא יכול לנהל אותו.\nאפשר להשתמש ב-kubectl annotate לסמן אותו כmanaged by Helm, או למחוק ולאפשר ל-Helm ליצור מחדש."},
    {q:"ה-PV נמחק בזמן שPVC עדיין קיים. PVC עכשיו בסטטוס 'Lost'. מה עושים?",options:["מוחקים את ה-PVC ומחכים","יוצרים PV חדש עם claimRef שמצביע על ה-PVC הקיים","kubectl restart pvc","מחיקת namespace"],answer:1,explanation:"כש-PV נמחק, ה-PVC עובר לסטטוס Lost.\nיש ליצור PV חדש עם spec.claimRef שמצביע על הnamespace/שם של ה-PVC הקיים, כך ה-binding יוחזר."},
    {q:"ה-Pod מנסה לכתוב לvolume אך מקבל 'Read-only file system'. PVC מוגדר ב-YAML. מה בודקים?",options:["accessMode ReadWriteOnce בPVC לא תומך בכתיבה","volumeMounts.readOnly: true מוגדר ב-Pod spec – מסיר את זה","image שגוי","חסר Secret"],answer:1,explanation:"אם volumeMounts מוגדר עם readOnly: true, ה-container לא יכול לכתוב לvolume גם אם ה-PVC מרשה זאת.\nיש להסיר readOnly: true מה-volumeMounts."},

    // ── Troubleshooting ──
    {q:"ה-Node עבר לסטטוס NotReady פתאום. מה הצעד הראשון לאבחון?",options:["מחיקת כל הPods שעל ה-Node","kubectl describe node ו-ssh ל-Node לבדוק kubelet logs","kubectl delete node","rollback של אשכול"],answer:1,explanation:"kubectl describe node יציג conditions ולחלץ מידע על הסיבה (DiskPressure, MemoryPressure, NetworkUnavailable).\nלאחר מכן SSH ל-Node ובדיקת: systemctl status kubelet."},
    {q:"ה-Pod תקוע בסטטוס Terminating כבר 30 דקות. kubectl delete לא עוזר. מה עושים?",options:["chmod על ה-Pod","kubectl delete pod <name> --force --grace-period=0","kubectl restart pod","חיכוי של שעה"],answer:1,explanation:"Pod שתקוע ב-Terminating בד\"כ חכה ל-finalizer שלא הסתיים. --force --grace-period=0 מאלץ מחיקה מיידית. יש להשתמש בזהירות בproduction."},
    {q:"הפקודה kubectl exec לא עובד על Pod. מקבל 'error: unable to upgrade connection: container not found'. מה הסיבה?",options:["RBAC חסר","ה-container כבר נסגר – Pod אולי ב-CrashLoop","image שגוי","Node תקוע"],answer:1,explanation:"kubectl exec פותח connection ל-container רץ.\nאם ה-container נסגר (CrashLoop), אין container שניתן ל-exec אליו.\nיש לבדוק logs ולתקן את הגורם לקריסה."},
    {q:"ה-Cluster Autoscaler לא מוסיף Nodes למרות Pods ב-Pending. מה בודקים?",options:["kubectl get pods","לוגים של cluster-autoscaler Pod – ייתכן שיש taint/toleration mismatch, quota, או שאין instance type זמין","kubectl describe node","DNS"],answer:1,explanation:"הAutoscaler מוסיף Nodes רק אם הוא מזהה שPods יכולים לרוץ על Node חדש.\nאם יש taint שה-Pod לא מסיים, quota שהתמלאה, או בעיה בcloud provider, הוא לא יוסיף."},
    {q:"ה-Node מציג DiskPressure. Pods מתחילים להיות evicted. מה הפתרון המהיר?",options:["יצירת PVC","ניקוי images, logs וקבצים זמניים בNode – docker system prune", "הגדלת memory limits","שינוי namespace"],answer:1,explanation:"DiskPressure מתרחש כשדיסק ה-Node מתמלא.\nהפתרון המהיר: SSH ל-Node, ניקוי images לא בשימוש (docker/crictl image prune) ולוגים ישנים.\nלטווח ארוך: הגדלת דיסק או שימוש ב-log rotation."},
    {q:"הפקודה kubectl top nodes נכשלת: 'error: Metrics API not available'. מה חסר?",options:["RBAC","metrics-server לא מותקן באשכול","DNS","StorageClass"],answer:1,explanation:"kubectl top דורש את metrics-server שמספק CPU/memory metrics.\nללא זה, גם HPA לא יעבוד.\nמתקינים: kubectl apply -f https://github.com/kubernetes-sigs/metrics-server/releases/latest/download/components.yaml"},
    {q:"הפקודה kubectl drain node1 נחסם: 'cannot delete Pods not managed by ReplicationController, ReplicaSet, Job, DaemonSet, or StatefulSet'. מה עושים?",options:["kubectl delete node","מוסיפים --force --ignore-daemonsets","kubectl uncordon","יצירת PDB"],answer:1,explanation:"kubectl drain נחסם כש-Pods standalone (ללא controller) קיימים על ה-Node. -force מאפשר למחוק אותם. -ignore-daemonsets מתעלם מ-DaemonSet Pods שלא ניתן להזיז."},
    {q:"בדיקת Liveness probe מוגדר על path /healthz ומכשילה כל 30 שניות. הContainer מופעל מחדש כל פעם. האפליקציה עובדת. מה בודקים?",options:["resource limits","ה-liveness probe מגיעה לendpoint שגוי (port/path) או שהתגובה לא 200","image שגוי","NetworkPolicy"],answer:1,explanation:"אם האפליקציה עובדת אבל liveness probe מכשילה, כנראה שה-probe מוגדרת עם port או path שגוי, או שה-endpoint מחזיר status code שאינו 200-399.\nיש לוודא שהpath והport תואמים את ה-health endpoint של האפליקציה."},
    {q:"אחרי kubectl rollout undo, הDeployment חזר לגרסה קודמת אבל האפליקציה עדיין שבורה. מה בודקים?",options:["kubectl delete deployment","ייתכן שundone חזר לrevision שגם הוא שבור – בודקים rollout history ובוחרים revision ספציפי","kubectl get nodes","DNS"],answer:1,explanation:"kubectl rollout undo חוזר ל-revision הקודם, אבל אם גם הוא היה שבור, זה לא יעזור. kubectl rollout history deployment/my-app מציג את כל ה-revisions, ואפשר לחזור ל-revision ספציפי עם --to-revision=N."},
    {q:"הפקודה kubectl apply -f manifest.yaml עובד בלי שגיאות, אבל המשאב לא נוצר. מה בודקים?",options:["kubectl delete namespace","kubectl get events -n <namespace> ו-kubectl get <resource> -n <namespace> – ייתכן שהוא נוצר ב-namespace שגוי","RBAC","image"],answer:1,explanation:"apply מצליח מבחינת API server, אבל ה-resource נוצר ב-namespace הגדרת ב-YAML (שאולי שגוי) או ב-default.\nיש לבדוק kubectl get <resource> --all-namespaces."},
    {q:"ה-Pod חדש לא יכול להיות scheduled על אף Node. kubectl describe pod מציג Taints. מה הפתרון?",options:["מחיקת ה-Pod","הוספת toleration ל-Pod spec שתואמת ל-taint של ה-Nodes","הגדלת CPU","שינוי namespace"],answer:1,explanation:"כש-Node מסומן עם taint, רק Pods שיש להם toleration מתאים יוכלו לרוץ עליו.\nיש להוסיף ב-Pod spec תחת tolerations: ערך שתואם ל-taint (key, operator, effect)."},
    {q:"ה-etcd Pod בkube-system מציג בעיות. כמה etcd members יש לאשכול בריא בproduction?",options:["1","2","3 (או מספר אי-זוגי)","5 בהכרח"],answer:2,explanation:"etcd דורש quorum – רוב החברים חייבים להיות זמינים. 3 members מאפשרים כשל של 1. 5 מאפשרים כשל של 2.\nתמיד מספר אי-זוגי כדי למנוע split-brain.\nלproduction נהוג 3 או 5."},
    {q:"ה-Namespace נמחק אבל תקוע בסטטוס Terminating. kubectl get namespace מציג Terminating כבר שעה. מה הסיבה?",options:["אין RBAC","יש finalizers על resources בתוך ה-namespace שמונעים מחיקה","DNS כשל","etcd בעיה"],answer:1,explanation:"Namespace ב-Terminating בד\"כ תקוע בגלל finalizers שלא הוסרו. יש לזהות את ה-resources עם finalizers (בד\"כ CRDs) ולהסיר אותם ידנית. ניתן לערוך ה-namespace ולמחוק finalizers מה-spec."},
    {q:"ה-Pod רץ על Node1. kubectl drain node1 בוצע. אחרי כמה זמן ה-Pod עובר ל-Node אחר?",options:["מיידית – Kubernetes מזיז Pods בזמן drain","drain מסיים את ה-Pod ואחראי ה-controller (Deployment) יצור Pod חדש על Node אחר","Pod לא יכול לעבור Node","שעה אחרי"],answer:1,explanation:"kubectl drain מסיים (terminates) את ה-Pod על ה-Node.\nה-Deployment controller, שמבחין שחסר replica, יצור Pod חדש שה-Scheduler ישים על Node אחר (שאינו cordoned)."},
    {q:"מערכת RBAC מוגדרת עם ClusterRole אבל ב-namespace ספציפי. איזה binding משתמשים?",options:["ClusterRoleBinding בלבד","RoleBinding – מאפשר שימוש בClusterRole אבל רק בnamespace של ה-RoleBinding","Role","ServiceAccount"],answer:1,explanation:"RoleBinding יכול להתייחס לClusterRole, אבל מגביל את ההרשאות ל-namespace של ה-RoleBinding עצמו.\nClusterRoleBinding יתן הרשאות על כל האשכול.\nלscoped access – משתמשים ב-RoleBinding עם ref ל-ClusterRole."},
    {q:"ה-Pod ב-namespace prod מנסה לקבל ConfigMap מnamespace staging. מה קורה?",options:["זה עובד אוטומטית","Pods לא יכולים לגשת ישירות לresources בnamespaces אחרים","צריך ClusterRole","צריך NetworkPolicy"],answer:1,explanation:"Pods ניגשים לConfigMaps, Secrets, וresources אחרים רק בתוך ה-namespace שלהם.\nכדי לשתף data בין namespaces, יוצרים עותק בכל namespace או משתמשים ב-external config store."},
    {q:"שדה readinessGate מוגדר על Pod. Pod מציג READY 0/1 למרות שreadiness probe מצליחה. מה בודקים?",options:["liveness probe","readinessGate condition לא נענה – חיצוני לK8s (כגון load balancer sync)","image","DNS"],answer:1,explanation:"readinessGates מאפשרים לגורמים חיצוניים לK8s לקבוע readiness.\nPod יהיה Ready רק אחרי שה-condition הנוסף (למשל network load balancer sync) מוגדר כTrue בstatus.\nיש לבדוק את ה-custom conditions."},
    {q:"נתת kubectl apply על PodDisruptionBudget. drain של Node נכשל: 'Cannot evict pod as it would violate the pod's disruption budget'. מה קרה?",options:["Node בעיה","PDB מגדיר minAvailable=2 אך יש רק 2 Pods – drain יוריד את המספר מתחת לminimum","StorageClass בעיה","NetworkPolicy"],answer:1,explanation:"PDB מגדיר כמה Pods חייבים להישאר זמינים.\nאם drain ינסה למחוק Pod שיוריד את הכמות מתחת ל-minAvailable, הוא יחסום.\nהפתרון: לוודא שיש replicas מספיקות לפני drain, או להגדיל את הDeployment."},
    {q:"בdebug של אפליקציה, מריצים kubectl exec pod -- env ורואים שמשתנה SECRET_KEY לא קיים. מה בודקים?",options:["RBAC","האם ה-Secret קיים בnamespace, ואם valueFrom.secretKeyRef נכון ב-YAML של ה-Pod","DNS","NetworkPolicy"],answer:1,explanation:"כשenv var מ-Secret חסר, הסיבות האפשריות: ה-Secret לא קיים, secretName שגוי, key שגוי, או namespace שגוי. kubectl get secret <name> -n <namespace> ו-kubectl describe pod לבדיקת status."},
    {q:"ה-Pod A מנסה לגשת לPod B בport 8080. מחזיר connection timeout. NetworkPolicy לא מוגדרת. מה בודקים?",options:["ה-Pod B בport 8080 לא מאזין – תהליך לא עלה","RBAC","StorageClass","Ingress"],answer:0,explanation:"ללא NetworkPolicy, traffic מוגבל רק על ידי הProcess עצמו.\nאם timeout ולא refused – ייתכן שהPod B לא מאזין על ה-port הנכון.\nבודקים: kubectl exec podB -- netstat -tlnp."},
    {q:"ה-Deployment עם 3 replicas. כל הPods מציגים ImagePullBackOff. kubectl describe מציג 'Back-off pulling image'. מה הצעד הראשון?",options:["מחיקת ה-Deployment","בדיקת image tag ב-YAML – האם הtag קיים בregistry","kubectl get nodes","etcd בדיקה"],answer:1,explanation:"ImagePullBackOff אומר שלא ניתן למשוך את ה-image.\nהסיבות הנפוצות: tag לא קיים, שם image שגוי, או חוסר ב-imagePullSecrets לprivate registry. kubectl describe pod יציג את ה-image name המדויק."},
    {q:"אשכול Kubernetes גדול. נרצה לוודא שPods ייפרסו על Nodes בzones שונות לHA. איך עושים זאת?",options:["Node affinity בלבד","topology spread constraints עם topologyKey: topology.kubernetes.io/zone","DaemonSet","StatefulSet"],answer:1,explanation:"topologySpreadConstraints מאפשרים הגדרה שPods יתפזרו באופן שווה על פני zones (או nodes, racks).\nמגדירים maxSkew ו-topologyKey לzone.\nזה עדיף על anti-affinity כי הוא גמיש ומדרגי יותר."},
    {q:"ה-Pod ב-CrashLoop. הלוגים מציגים permission denied על path /data. מה הבעיה?",options:["חסר PVC","ה-container רץ כuser שאין לו הרשאות לwrite ל-/data – בודקים securityContext.runAsUser ו-fsGroup","image שגוי","namespace"],answer:1,explanation:"כשprocess בתוך container מנסה לכתוב לpath שלו אין הרשאות, נקבל permission denied.\nפתרונות: הגדרת fsGroup ב-securityContext, שינוי ownership בDockerfile, או הרצה כuser עם הרשאות מתאימות."},
    {q:"ה-Namespace מוגדר עם ResourceQuota: requests.cpu=2. Pod חדש מבקש cpu: 4. מה קורה?",options:["Pod מקבל 2 cpu","Pod נדחה – עובר את ה-quota","Pod מקבל 4 cpu","Pod נשאר Pending"],answer:1,explanation:"ResourceQuota אוכפת מגבלות על צריכת משאבים בnamespace.\nPod שדורש יותר ממה שנשאר ב-quota יידחה בזמן יצירה עם שגיאת 403."},
    {q:"ה-LimitRange מוגדר בnamespace עם default cpu limit=500m. Pod נוצר ללא cpu limit. מה ה-cpu limit של ה-Pod?",options:["אין limit","500m מה-LimitRange","1 core","ללא הגבלה"],answer:1,explanation:"LimitRange מגדיר ערכי ברירת מחדל לresources.\nPod שנוצר ללא limits יקבל את ה-defaults מה-LimitRange של ה-namespace אוטומטית."},
    {q:"ה-DaemonSet מוגדר אך לא רץ על Node חדש שנוסף. מה הסיבה הסבירה?",options:["DaemonSet צריך restart","ל-Node יש Taint שה-DaemonSet אין toleration בשבילו","image שגוי","namespace שגוי"],answer:1,explanation:"DaemonSet מריץ Pod על כל Node, אלא אם ל-Node יש Taint שה-DaemonSet לא מקבל.\nיש להוסיף toleration מתאים ל-DaemonSet spec."},
    {q:"רוצים שPods של service A לא ירוצו על אותו Node כמו Pods של service B. מה מגדירים?",options:["nodeSelector","pod anti-affinity עם topologyKey: kubernetes.io/hostname","NetworkPolicy","ResourceQuota"],answer:1,explanation:"Pod anti-affinity עם topologyKey: kubernetes.io/hostname מבטיחה שPods עם labels מסוימים לא ישכנו על אותו Node.\nשימושי לHA ולהפרדת workloads."},
    {q:"ה-HPA מוגדר min=2 max=10 targetCPU=50%. יש 2 Pods ב-CPU 80%. כמה Pods אחרי scale-up?",options:["10","4","3","2"],answer:1,explanation:"HPA מחשב: ceil(currentReplicas × actualMetric/targetMetric) = ceil(2 × 80/50) = ceil(3.2) = 4 replicas.\nScale-up הדרגתי, לא קפיצה למקסימום."},
    {q:"הפקודה kubectl rollout pause deployment/my-app – מה זה עושה?",options:["עוצר את כל ה-Pods","עוצר updates זמנית – שינויים נוספים לא יגרמו לrollout עד ל-resume","מוחק את ה-Deployment","מבצע scale=0"],answer:1,explanation:"rollout pause מאפשר לצבור מספר שינויים ב-Deployment spec ולהחיל אותם בבת אחת עם rollout resume.\nשימושי לcanary testing."},
    {q:"ה-Pod יצא עם exit code 137. מה המשמעות?",options:["הצלחה (0)","ה-container קיבל SIGKILL – בד\"כ OOMKill","ה-container קיבל SIGTERM","שגיאת network"],answer:1,explanation:"Exit code 137 = 128+9 (SIGKILL).\nהסיבות הנפוצות: OOMKilled (kernel הרג בגלל memory limit) או kubectl delete --force.\nבודקים kubectl describe pod לאשר."},
    {q:"ה-Multi-container Pod עם sidecar. שני ה-containers צריכים לשתף קבצים. מה הפתרון?",options:["PVC נפרד","emptyDir volume שמחובר לשני ה-containers","ConfigMap","NetworkPolicy"],answer:1,explanation:"emptyDir נוצר עם ה-Pod ונמחק איתו.\nשני containers יכולים לחבר אותו ב-paths שונים ולשתף קבצים.\nזהו הפתרון הסטנדרטי לshared filesystem בתוך Pod."},
    {q:"ה-Pod מוגדר עם hostPath volume ל-/var/run/docker.sock. מה הסיכון?",options:["אין סיכון","ה-container מקבל גישה ל-Docker daemon של ה-Node – אפשר לברוח מה-container לחלוטין","רק read-only","ביצועים נמוכים"],answer:1,explanation:"גישה ל-docker.sock מאפשרת לcontainer להפעיל containers אחרים על ה-Node, לקרוא secrets, ולתקוף את ה-host.\nזהו container escape vector קלאסי.\nנמנעים ממנו בproduction."},
    {q:"אחסון emptyDir עם medium: Memory מוגדר. מה שונה מemptyDir רגיל?",options:["נשמר לאחר restart","נשמר ב-RAM (tmpfs) – מהיר יותר אבל צורך memory","מוגדל אוטומטית","נשמר ב-etcd"],answer:1,explanation:"emptyDir medium: Memory יוצר tmpfs (RAM-based filesystem).\nמהיר מאוד אבל צורך memory מהPod.\nשימושי לcaches עתירי I/O.\nהנתונים נמחקים עם ה-Pod."},
    {q:"מנגנון PodSecurityAdmission ב-namespace עם enforce=restricted. Pod ניסה לרוץ ב-privileged mode. מה קרה?",options:["Pod רץ ב-privileged","Pod נדחה ב-admission","Pod רץ ב-reduced mode","RBAC מנע"],answer:1,explanation:"Policy restricted אוסרת privileged containers, hostPath volumes, running as root.\nPod שמנסה לחרוג נדחה לפני יצירה על ידי ה-admission controller."},
    {q:"ה-Pod מוגדר עם terminationGracePeriodSeconds: 0. מה קורה כשמוחקים אותו?",options:["Pod ממתין 30 שניות","SIGKILL נשלח מיידית – ללא זמן cleanup","Pod ממשיך לרוץ","SIGTERM ואז SIGKILL אחרי שנייה"],answer:1,explanation:"terminationGracePeriodSeconds: 0 אומר שK8s שולח SIGKILL מיידית ללא SIGTERM.\nהprocess לא מקבל זמן לcleanup.\nשימושי בtest environments, מסוכן בproduction."},
    {q:"ה-Deployment עם strategy: Recreate. מה קורה בupgrade?",options:["Rolling update – Pod אחד בכל פעם","כל ה-Pods ישנים נמחקים תחילה ואז Pods חדשים נוצרים – יש downtime","אין שינוי","Blue/Green אוטומטי"],answer:1,explanation:"Recreate strategy גורמת לdowntime מכוון.\nK8s מסיים את כל ה-Pods הישנים ורק אז יוצר חדשים.\nמתאים כשאי אפשר להריץ שתי גרסאות במקביל (single-writer DB)."},
    {q:"הפקודה kubectl apply -f secret.yaml. הSecret נוצר. אחר כך kubectl apply מחדש עם ערכים שונים. מה קורה?",options:["שגיאה – Secret קיים","Secret מתעדכן עם הערכים החדשים","Secret כפול נוצר","שום דבר"],answer:1,explanation:"kubectl apply הוא declarative – אם resource קיים, הוא מתעדכן לפי ה-YAML החדש.\nבניגוד ל-create שנכשל אם קיים.\nעדכון Secret עם apply חל על Pods חדשים; Pods קיימים לא מושפעים."},
    {q:"מערכת Kubernetes Ingress Controller לא מותקן. Ingress object נוצר. מה קורה?",options:["Ingress עובד עם kube-proxy","Object נוצר ב-etcd אבל לא מתפקד – אין traffic routing","DNS נכשל","Pods נמחקים"],answer:1,explanation:"Ingress object הוא רק ה-API definition.\nבלי Ingress Controller (nginx, traefik, ALB) שיממש אותו, ה-Ingress לא עושה כלום.\nController צריך להיות מותקן קודם."},
    {q:"ה-Pod צריך לדעת את שמו ואת ה-namespace שלו בזמן ריצה. מה משתמשים?",options:["ConfigMap ידני","Downward API – מזריק metadata של ה-Pod כenv vars","Secret","kubectl env inject"],answer:1,explanation:"Downward API מאפשר לPod לקרוא metadata עצמי (name, namespace, labels, annotations, resources) כenv vars או volume files – ללא ConfigMap חיצוני."},
    {q:"ה-Service Account Token מוזרק ל-Pod. מה ה-path בתוך ה-container?",options:["/etc/secrets","/var/run/secrets/kubernetes.io/serviceaccount","/sa/token","/k8s/token"],answer:1,explanation:"K8s מחבר ServiceAccount token ל-/var/run/secrets/kubernetes.io/serviceaccount/token.\nגם ca.crt ו-namespace שם.\nהאפליקציה קוראת token לשם אימות מול API server."},
    {q:"הפקודה kubectl get pods מחזיר 'The connection to the server was refused'. מה הבעיה?",options:["Pods לא קיימים","API server לא פועל או kubeconfig מצביע ל-endpoint שגוי","namespace שגוי","RBAC"],answer:1,explanation:"connection refused ל-API server אומר שהתהליך לא מאזין.\nסיבות: API server crashed, kubeconfig שגוי, VPN/network בעיה.\nבודקים: kubectl config view, ping ל-API server IP."},
    {q:"פקודת Helm install נכשל: 'release already exists'. מה עושים?",options:["kubectl delete release","helm upgrade --install <release> <chart> – מטפל בשני המקרים","kubectl delete namespace","helm delete chart"],answer:1,explanation:"helm install נכשל אם release קיים. helm upgrade --install ימשיך לעבוד בין אם release קיים (upgrade) ובין אם לא (install).\nפתרון אחיד לשני המקרים."},
    {q:"ה-ConfigMap מוגדר כenv vars. ConfigMap נמחק. ה-Pod הרץ מושפע?",options:["Pod קורס מיידית","Pod ממשיך לרוץ – env vars הוזרקו בזמן יצירה","ConfigMap מוחזר אוטומטית","Pod מופעל מחדש"],answer:1,explanation:"Env vars מConfigMap מוזרקים לPod בזמן יצירה ונשמרים בmemory של ה-process.\nמחיקת ConfigMap לא משפיעה על Pod רץ.\nPod חדש שינסה לעלות יכשל."},
    {q:"ה-Pod מוגדר עם activeDeadlineSeconds: 300 בJob. מה קורה אחרי 5 דקות?",options:["Pod מושהה","Pod מסומן כFailed ומסיים","Pod מופעל מחדש","שום דבר"],answer:1,explanation:"activeDeadlineSeconds מגדיר זמן מקסימלי לJob/Pod.\nאחרי שעבר, K8s מסיים ומסמן כFailed.\nשימושי למניעת Jobs שרצים לנצח."},
    {q:"תהליך Rolling update יצר שתי גרסאות שרצות במקביל. מה חשוב לוודא?",options:["version lock","backward compatibility – DB schema וAPI responses חייבים לתמוך בשתי גרסאות","rollback מיידי","כלום"],answer:1,explanation:"בזמן rolling update שתי גרסאות רצות יחד.\nDB migrations לא יכולות להיות destructive.\nAPI responses חייבות להיות תואמות לשתי גרסאות.\nזהו עיקרון backward compatibility."},
    {q:"ה-Service ExternalName מוגדר. מה הוא עושה?",options:["פותח port חיצוני","יוצר DNS CNAME alias לexternal hostname – ללא proxying","מאפשר גישה מחוץ לcluster","מגדיר firewall rule"],answer:1,explanation:"ExternalName service יוצר CNAME DNS שמפנה לexternal hostname (כמו my-db.external.com).\nPods באשכול גישים לשירות חיצוני כאילו הוא internal service."},
    {q:"ברשימת initContainers: initContainer-2 ממתין ל-initContainer-1. מה ה-behavior?",options:["שניהם מתחילים במקביל","K8s ממתין ש-initContainer-1 יסיים (exit 0) לפני initContainer-2","Container הראשי מתחיל מיד","Pod נמחק"],answer:1,explanation:"init containers רצים sequentially – אחד בכל פעם.\nK8s מחכה שכל init container יסיים לפני הבא.\nרק אחרי שכולם הסתיימו, main containers עולים."},
    {q:"כלל ה-NetworkPolicy: podSelector: {} (ריק). מה זה מתאר?",options:["שום Pod","כל ה-Pods בnamespace","כל ה-Pods בכל namespaces","שגיאה בsyntax"],answer:1,explanation:"empty podSelector ב-NetworkPolicy policy spec בוחר כל ה-Pods בnamespace.\nשונה מnamespaceSelector: {} שבוחר כל הnamespaces.\nחשוב להבדיל."},
    {q:"מערכת Kubernetes Secret גדול מ-1MiB. מה קורה?",options:["נוצר עם אזהרה","נדחה – K8s מגביל objects ל-1MiB","נוצר ב-etcd partition נפרד","Secret מחולק אוטומטית"],answer:1,explanation:"etcd ו-K8s enforces גבול של 1MiB per object (Secret/ConfigMap).\nלנתונים גדולים, משתמשים בexternal secret store (HashiCorp Vault, AWS Secrets Manager)."},
    {q:"ה-Pod צריך גישה ל-AWS S3 ללא credentials ב-Kubernetes. מה הגישה המומלצת?",options:["Secret עם Access Key","IRSA (IAM Roles for Service Accounts) – K8s SA מחובר ל-AWS IAM Role","ConfigMap עם ARN","hostPath"],answer:1,explanation:"IRSA מאפשר לPod לקבל AWS credentials זמניות דרך projected ServiceAccount token.\nללא Secret, ללא rotation ידני.\nבGKE: Workload Identity.\nב-Azure: Workload Identity Federation."},
    {q:"ה-Pod ב-namespace prod מנסה לגשת לService ב-namespace staging. מה ה-DNS הנכון?",options:["my-svc","my-svc.staging","my-svc.staging.svc.cluster.local","staging/my-svc"],answer:2,explanation:"Full DNS name בK8s: <service>.<namespace>.svc.cluster.local.\nלגישה לservice בnamespace אחר חייבים FQDN או לפחות <service>.<namespace>."},
    {q:"הפקודה kubectl cordon node1 – מה ההבדל מdrain?",options:["זהה לחלוטין","cordon מסמן Node כunschedulable אבל לא מסיר Pods קיימים; drain גם מסיר Pods","cordon מוחק Pods","drain לא ניתן לביטול"],answer:1,explanation:"cordon: Node לא יקבל Pods חדשים (unschedulable), Pods קיימים ממשיכים לרוץ. drain: cordon + evicts כל Pods שאינם DaemonSets. cordon בלבד משמש לmaintenance הדרגתי."},
    {q:"ה-VPA (Vertical Pod Autoscaler) במצב Auto. מה הוא עושה?",options:["מוסיף Nodes","מכוון resources requests/limits ומפעיל Pods מחדש לפי הצורך","מגדיל replicas","לא עושה כלום"],answer:1,explanation:"VPA Auto mode: מחשב resource recommendations ומיישם אותן על ידי eviction + recreate של Pods.\nזה גורם לdowntime קצר.\nבשל כך, VPA ו-HPA לא מומלצים יחד על אותו Deployment."},
    {q:"ה-CronJob יצר יותר ממדיניות ה-concurrencyPolicy. Pod ישן עדיין רץ. מה קורה?",options:["Job חדש נוצר תמיד","בהתאם ל-concurrencyPolicy: Forbid – Job חדש לא ייצר; Replace – Job ישן נמחק","שני Jobs רצים במקביל תמיד","CronJob מושהה"],answer:1,explanation:"concurrencyPolicy: Allow (ברירת מחדל) – Jobs מקבילים.\nForbid – Job חדש לא ייצר אם קודמו עדיין רץ.\nReplace – Job ישן נמחק ונוצר חדש.\nחשוב לבחור נכון לפי workload."},
    {q:"ה-Pod צריך לרוץ על Node ספציפי לפי hostname. מה הדרך הפשוטה ביותר?",options:["NetworkPolicy","nodeName: <node-name> ב-Pod spec","nodeSelector","taint"],answer:1,explanation:"nodeName שולח Pod ישירות ל-Node ספציפי, עוקף את ה-Scheduler לחלוטין.\nפשוט אך לא גמיש.\nלproduction מועדפים nodeSelector או node affinity שמאפשרים label-based matching."},
    {q:"מערכת Kubernetes API server זמין. kubectl get pods אבל לא רואה changes חדשים. מה בודקים?",options:["etcd","kubectl cache – מוסיפים --no-cache","watch לא פועל","RBAC"],answer:1,explanation:"kubectl מחזיק cache מקומי. -no-cache מאלץ קריאה ישירה מ-API server.\nלעיתים cache ישן גורם להצגת נתונים לא מעודכנים, במיוחד לאחר שינויים רבים."},
    // ── Workloads extra ──
    {q:"ה-Deployment עם 3 replicas. מה קורה לאחר kubectl scale deployment/app --replicas=0?",options:["Deployment נמחק","כל ה-Pods מסתיימים; ה-Deployment נשמר ללא Pods","Pod אחד נשאר","מתקבלת שגיאה"],answer:1,explanation:"scale --replicas=0 מסיים את כל ה-Pods אבל שומר את ה-Deployment ואת ה-ReplicaSet.\nשימושי לחיסכון במשאבים בסביבות dev.\nלהחזרה: kubectl scale --replicas=3."},
    {q:"ה-Pod נתקע ב-Terminating כבר 20 דקות. kubectl delete pod לא עוזר. מה עושים?",options:["מאתחלים Node","kubectl delete pod <name> --force --grace-period=0 ובדיקת finalizers","מוחקים namespace","etcd restore"],answer:1,explanation:"Terminating תקוע לרוב בגלל finalizer שלא נוקה. kubectl patch pod <name> -p '{\"metadata\":{\"finalizers\":null}}' מסיר finalizers בכפייה. --force מאלץ מחיקה מיידית."},
    {q:"ה-Init container נכשל שוב ושוב. מה הסטטוס של ה-Pod?",options:["Running","Init:CrashLoopBackOff","Pending","Error"],answer:1,explanation:"כשinit container קורס חוזר ונשנה, Pod יציג Init:CrashLoopBackOff.\nבדוק בlogs: kubectl logs <pod> -c <init-container-name> --previous."},
    {q:"ה-StatefulSet עם 3 replicas. Pod-1 קרס. מה Kubernetes עושה?",options:["מוחק את כולם ומתחיל מחדש","מפעיל מחדש רק Pod-1; Pods 0 ו-2 ממשיכים","מעלה Pod-3 במקום","ממתין לPod-0 לקרוס"],answer:1,explanation:"StatefulSet מנהל כל Pod באופן עצמאי עם identifier קבוע.\nרק Pod-1 יופעל מחדש.\nה-PVC של Pod-1 נשמרת ומחוברת שוב לPod החדש."},
    {q:"ה-DaemonSet לא מופיע על Node חדש שנוסף לאשכול. מה הסיבה?",options:["DaemonSet לא תומך ב-Nodes חדשים","Node מסומן כunschedulable או יש Taint שה-DaemonSet לא tolerates","מקסימום Pods הגיע","namespace שגוי"],answer:1,explanation:"אם Node חדש מגיע עם Taint שה-DaemonSet לא tolerates, ה-Pod לא יתוזמן.\nבדוק: kubectl describe node <name> לTaints.\nהוסף toleration ל-DaemonSet spec."},
    {q:"ה-Job עם parallelism=3, completions=9. כמה Pods ירוצו בו-זמנית בשיא?",options:["9","3","1","6"],answer:1,explanation:"parallelism=3 קובע מקסימום 3 Pods במקביל. completions=9 קובע את מספר ההצלחות הנדרשות.\nה-Job ירוץ 3 גלים של 3 Pods עד להשגת 9 הצלחות."},
    {q:"ה-Pod מסולק (Evicted). מה הסיבה הנפוצה ביותר?",options:["CPU limit חרג","Node תחת memory pressure – kubelet מסלק Pods לפי QoS","Pod נמחק ידנית","Image לא נמצא"],answer:1,explanation:"kubelet עוקב אחר resource pressure.\nכשיש memory pressure, הוא מסלק Pods: BestEffort ראשון, Burstable שני, Guaranteed אחרון.\nEviction שונה ממחיקה – Controller מפעיל Pod חדש."},
    {q:"ה-Deployment עם maxUnavailable=0, maxSurge=1. מה קורה בrollout?",options:["אין rollout","Pod חדש עולה לפני שישן יורד – אין downtime","Pod ישן נמחק קודם","אין הגבלה"],answer:1,explanation:"maxUnavailable=0: אי אפשר להוריד Pod עד שהחדש Ready. maxSurge=1: מותר Pod אחד נוסף מעל הdesired.\nתוצאה: rollout ללא downtime – Pod חדש עולה → Pod ישן יורד."},
    {q:"ה-Pod עם priorityClassName גבוה. לא נמצא מקום בcluster. מה קורה?",options:["Pod ממתין ב-Pending","Pod בעדיפות גבוהה גורם לpreemption של Pods בעדיפות נמוכה","Pod נמחק","priorityClass לא משפיע"],answer:1,explanation:"Preemption: ה-Scheduler מסלק Pods בעדיפות נמוכה כדי לפנות מקום ל-Pod בעדיפות גבוהה.\nחשוב להגדיר PriorityClasses בזהירות כדי למנוע פגיעה בworkloads קריטיים."},
    {q:"ה-ResourceQuota הגיעה לגבול. Pod חדש נוצר. מה קורה?",options:["Pod רץ בכל מקרה","Pod נדחה עם שגיאת 'exceeded quota'","Pod ממתין ב-Pending","ResourceQuota גדלה אוטומטית"],answer:1,explanation:"כשResourceQuota מוצתה, API server דוחה יצירת resources חדשים עם שגיאה מפורשת. kubectl describe resourcequota -n <ns> יציג שימוש נוכחי מול הגבול."},
    {q:"ה-LimitRange מגדיר default memory request=256Mi. Pod נוצר ללא memory request. מה קורה?",options:["Pod נדחה","Pod מקבל אוטומטית request=256Mi","Pod רץ ללא request","שגיאת validation"],answer:1,explanation:"LimitRange יכול להזריק default requests/limits לPods שלא הגדירו.\nPod שנוצר ב-namespace עם LimitRange יקבל defaults אוטומטית."},
    {q:"ה-Pod בסטטוס Unknown. מה הסיבה?",options:["API server לא מכיר את ה-Pod","kubelet לא מדווח – בד\"כ ה-Node אינו זמין","Pod חרג מlimits","Image לא נמצא"],answer:1,explanation:"Unknown מציין שה-Node אינו מדווח ל-control plane.\nבד\"כ קורה כשה-Node מת או מנותק. kubectl get node יציג NotReady לnode הרלוונטי."},
    {q:"ה-HPA לא מגדיל replicas למרות CPU גבוה. מה בודקים ראשון?",options:["Docker logs","metrics-server פעיל? kubectl top pods עובד?","StorageClass","Ingress"],answer:1,explanation:"HPA מסתמך על Metrics API.\nאם metrics-server לא פועל, kubectl top יחזיר שגיאה ו-HPA לא יוכל לקבל החלטות סקיילינג.\nבדוק: kubectl get apiservice v1beta1.metrics.k8s.io."},
    // ── Networking extra ──
    {q:"ה-Pod מנסה לגשת ל-Service בClusterIP ומקבל Connection refused. מה בודקים?",options:["DNS","kubectl get endpoints <service> – האם יש כתובות?","MTU","StorageClass"],answer:1,explanation:"Connection refused על ClusterIP לרוב אומר שה-Service אין Endpoints.\nבדוק kubectl get endpoints – אם ריק, בעיה ב-selector שלא תואם ל-Pods.\nגם ודא שה-Pods ב-Ready."},
    {q:"ה-Ingress מחזיר 404 לכל ה-paths. Pods עולים ו-Service קיים. מה הבעיה?",options:["TLS certificate","IngressClass לא מוגדר – Controller לא מטפל ב-Ingress","Pod יש שגיאה","namespace שגוי"],answer:1,explanation:"Ingress ב-K8s 1.18+ דורש spec.ingressClassName.\nאם חסר ולController אין default IngressClass, ה-Ingress לא מטופל ומקבלים 404."},
    {q:"כלל ה-NetworkPolicy קיימת. Pod A לא מגיע ל-Pod B באותו namespace. מה בודקים?",options:["Taint","podSelector של egress ב-A ו-ingress ב-B – שניהם נדרשים","kubectl get nodes","DNS"],answer:1,explanation:"NetworkPolicy עובדת בשני כיוונים.\nצריך: (1) egress מ-A ל-B מאופשר, (2) ingress ל-B מ-A מאופשר.\nCNI חייב לתמוך (Calico/Cilium כן, Flannel בסיסי – לא)."},
    {q:"ה-Service selector: app=backend. ה-Pod מוגדר עם label: app=Backend (B גדולה). מה קורה?",options:["Service פועל בכל מקרה","label selectors case-sensitive – Selector לא תואם, אין Endpoints","שגיאת API","Pod לא נוצר"],answer:1,explanation:"Label selectors case-sensitive. app=backend ≠ app=Backend.\nה-Service לא יצביע על שום Pod. kubectl get endpoints <service> יציג רשימה ריקה."},
    {q:"ה-Pod לא מצליח לפתור DNS של שירות חיצוני. CoreDNS פועל. מה בודקים?",options:["CoreDNS logs ו-upstream resolver","Ingress","StorageClass","RBAC"],answer:0,explanation:"CoreDNS פותר שמות חיצוניים על ידי forward ל-upstream.\nאם upstream לא מוגדר נכון ב-Corefile, DNS חיצוני ייכשל.\nבדוק גם NetworkPolicy שלא חוסמת outbound UDP 53."},
    {q:"שירות NodePort Service חשוף על port 32000. איך ניגשים מחוץ לאשכול?",options:["http://service-name:32000","http://<any-node-IP>:32000","http://ClusterIP:32000","http://localhost:32000"],answer:1,explanation:"NodePort פותח port על כל Node.\nגישה מחוץ לאשכול: http://<node-external-ip>:32000.\nאם יש LoadBalancer או Ingress עדיף להשתמש בהם."},
    {q:"ה-Pod לא מגיע לinternet. DNS פנימי ו-ClusterIP עובדים. מה בודקים?",options:["imagePullSecret","NAT/masquerade מוגדר? NetworkPolicy חוסמת egress?","StorageClass","RBAC"],answer:1,explanation:"גישה לinternet מPod עוברת דרך NAT.\nבדוק: (1) kube-proxy/CNI NAT rules, (2) NetworkPolicy egress שלא חוסמת 0.0.0.0/0, (3) Firewall על ה-Node."},
    {q:"ה-Ingress עם TLS. דפדפן מציג שגיאת certificate. Secret קיים. מה בודקים?",options:["DNS","Secret נמצא באותו namespace כמו ה-Ingress? ה-CN/SAN תואם לdomain?","kubelet","etcd"],answer:1,explanation:"TLS Secret חייב להיות באותו namespace כמו ה-Ingress.\nCertificate חייב להכיל CN/SAN של הdomain.\nבדוק: kubectl describe secret <tls-secret>."},
    {q:"ה-Service קיים אבל kubectl get endpoints מחזיר ריק. מה הסיבה?",options:["Service בnamespace שגוי","ה-Pods לא ב-Ready או ה-selector לא תואם","DNS כשל","StorageClass"],answer:1,explanation:"Endpoints נוצרים רק כשיש Pods עם matching labels שהם גם Ready.\nבדוק: kubectl get pods --show-labels ו-Service selector."},
    {q:"שירות Headless Service (clusterIP: None). מה DNS lookup על שם ה-Service מחזיר?",options:["ClusterIP יחיד","רשימת IP של Pods ישירות","שגיאת DNS","IP של Node"],answer:1,explanation:"Headless Service אינו מקבל ClusterIP.\nDNS מחזיר A records של כל ה-Pods.\nשימושי ל-StatefulSets ול-service discovery ישיר."},
    {q:"ה-Pod מגיע ל-Pod אחר דרך DNS אבל מקבל תוצאות ישנות. מה הסיבה?",options:["etcd לא מסונכרן","TTL של DNS cache – Pod מחזיק cache ישן","kubelet כשל","RBAC"],answer:1,explanation:"DNS responses מגיעות עם TTL.\nאפליקציות שcache-ות DNS עלולות להשתמש ב-IP ישן.\nפתרון: הורדת TTL ב-CoreDNS או שימוש ב-retry logic."},
    {q:"תוסף CNI plugin לא פועל על Node חדש. מה הסטטוס של Pods שמתוזמנים אליו?",options:["Running","ContainerCreating עם שגיאת network","Pending","Evicted"],answer:1,explanation:"ללא CNI פועל, K8s לא יכול להקצות IP לPod. kubectl describe pod יציג שגיאת 'network plugin not ready'.\nPod יישאר ContainerCreating."},
    {q:"שני Pods צריכים לתקשר ביניהם. מה הכתובת הנכונה בתוך cluster?",options:["IP של Pod (משתנה)","<service-name>.<namespace>.svc.cluster.local","hostname של Node","IP חיצוני"],answer:1,explanation:"תמיד עדיף להשתמש ב-Service DNS name ולא ב-Pod IP שמשתנה בכל restart.\nDNS pattern: <service>.<namespace>.svc.cluster.local.\nב-namespace זהה מספיק: <service-name>."},
    // ── Config & Security extra ──
    {q:"ה-Pod מנסה לקרוא Secret כ-env var ומקבל 'secret not found'. מה בודקים?",options:["RBAC","Secret קיים באותו namespace כמו ה-Pod?","StorageClass","CNI"],answer:1,explanation:"Secrets scoped ל-namespace.\nPod ב-namespace A לא יכול לגשת ל-Secret ב-namespace B.\nבדוק: kubectl get secret <name> -n <pod-namespace>."},
    {q:"הפקודה kubectl get pods מחזיר 'Error from server (Forbidden)'. מה הפתרון?",options:["kubectl restart","הגדר RoleBinding שמקשר User/ServiceAccount ל-Role עם get/list pods","שנה namespace","מחק etcd"],answer:1,explanation:"Forbidden = RBAC לא מאפשר את הפעולה.\nצריך: Role עם resources:[\"pods\"], verbs:[\"get\",\"list\"], ו-RoleBinding שמקשר ל-user/serviceaccount."},
    {q:"ה-ConfigMap עם מפתחות key1, key2. Pod מנסה לטעון key3. מה קורה?",options:["Pod רץ עם env var ריק","Pod לא עולה – 'key not found'","ConfigMap מתעדכן","namespace שגוי"],answer:1,explanation:"כשמשתמשים ב-valueFrom.configMapKeyRef עם key שלא קיים, ה-Pod לא יצליח להתחיל ויציג Event שגיאה.\nפתרון: בדוק שם המפתח ב-ConfigMap."},
    {q:"שדה imagePullSecret חסר ל-Pod שמשך image מprivate registry. מה הסטטוס?",options:["CrashLoopBackOff","ImagePullBackOff – K8s לא מצליח לאמת מול registry","ContainerCreating","Evicted"],answer:1,explanation:"בלי imagePullSecret, kubelet לא יוכל לאמת מול private registry.\nPod יציג ImagePullBackOff.\nפתרון: kubectl create secret docker-registry + imagePullSecrets בPod spec."},
    {q:"ה-Pod מנסה לרוץ כroot אבל PodSecurity standard=restricted. מה קורה?",options:["Pod רץ כroot","Pod נדחה – restricted מחייב runAsNonRoot:true","PodSecurity לא פעיל","warning בלבד"],answer:1,explanation:"PodSecurity Admission ב-restricted level מחייב runAsNonRoot:true, drop ALL capabilities ועוד.\nPod שלא עומד בכללים נדחה (Enforce mode)."},
    {q:"כלל ה-NetworkPolicy מגדירה default-deny-all. מה קורה לתעבורה ב-namespace?",options:["כלום משתנה","כל ingress ו-egress נחסמים אלא אם מאפשרים ב-NetworkPolicy מפורשת","DNS נחסם גם הוא","רק HTTP נחסם"],answer:1,explanation:"NetworkPolicy עם podSelector:{} ריק חוסמת כל תעבורה.\nיש להגדיר NetworkPolicies מפורשות לתעבורה מותרת.\nשים לב: גם DNS (port 53) נחסם!"},
    {q:"מה ההבדל בין Role ל-ClusterRole ב-RBAC?",options:["אין הבדל","Role scoped לnamespace; ClusterRole פועל על cluster-wide resources","ClusterRole חזק יותר ב-CPU","Role למasters בלבד"],answer:1,explanation:"Role: הרשאות בnamespace ספציפי.\nClusterRole: הרשאות לcluster-wide resources (Nodes, PVs, Namespaces) או בכל namespace דרך RoleBinding."},
    {q:"ה-Secret מוגדר עם value ב-base64. מה ה-bug הנפוץ בencoding?",options:["base64 לא תקין ב-K8s","echo 'value' | base64 מוסיף newline – יש להשתמש ב-echo -n","Secret מוצפן פעמיים","kubectl לא תומך base64"],answer:1,explanation:"echo 'value' | base64 מוסיף newline בסוף.\nהשתמש ב-echo -n 'value' | base64.\nנתוני Secret שגויים גורמים לאפליקציה לקבל ערך עם תו נוסף."},
    {q:"הפקודה kubectl פועל עם kubeconfig שהcertificate פג תוקפו. מה ה-Error?",options:["connection refused","Unauthorized (401) – Token/Cert לא תקף","RBAC Forbidden","DNS"],answer:1,explanation:"Certificate/Token שפג תוקפו מחזיר 401 Unauthorized.\nפתרון: עדכן kubeconfig עם credentials חדשים."},
    {q:"מנגנון Admission Webhook חוסם Deploy. מה עושים?",options:["מבטלים את ה-Webhook לצמיתות","מאבחנים את הסיבה מהmessage ומתקנים את ה-resource","מוחקים ה-Pod","RBAC"],answer:1,explanation:"Admission Webhooks מיישמים מדיניות.\nהמסר מסביר את הבעיה (חסר label, resource limit וכו').\nיש לתקן את ה-manifest, לא לעקוף את ה-Webhook."},
    {q:"ה-ServiceAccount של Pod מנסה לקרוא ConfigMaps אבל מקבל Forbidden. מה חסר?",options:["namespace","Role עם get/list ConfigMaps + RoleBinding לServiceAccount","ClusterRole","TLS cert"],answer:1,explanation:"הרשאות RBAC ניתנות ל-ServiceAccount.\nצריך: Role עם resources:[\"configmaps\"], verbs:[\"get\",\"list\"], ו-RoleBinding שמקשר ל-ServiceAccount של ה-Pod."},
    {q:"ה-Pod מוגדר עם securityContext.readOnlyRootFilesystem=true. אפליקציה כותבת ל-/tmp. מה קורה?",options:["כתיבה מותרת תמיד","כתיבה ל-/tmp נכשלת אלא אם /tmp הוא emptyDir volume","Pod נדחה","Root filesystem מוצפן"],answer:1,explanation:"readOnlyRootFilesystem מונע כתיבה לכל filesystem של ה-container.\nפתרון: הרכב emptyDir volume על /tmp לאפשר כתיבה זמנית בלי לפגוע באבטחה."},
    {q:"מערכת Kubernetes Secrets – מה האמת לגבי אבטחה?",options:["Secrets מוצפנים תמיד ב-etcd כברירת מחדל","Secrets מקודדים ב-base64 בלבד (לא מוצפנים) אלא אם מגדירים EncryptionConfiguration","Secrets לא נשמרים ב-etcd","Secret בטוח יותר מConfigMap"],answer:1,explanation:"ברירת מחדל, Secrets ב-etcd מקודדים base64 – לא מוצפנים.\nלהצפנה: הגדר EncryptionConfiguration ב-API server.\nלניהול secrets production: Vault, AWS Secrets Manager, External Secrets Operator."},
    // ── Storage extra ──
    {q:"ה-PVC בסטטוס Pending. StorageClass קיימת. מה בודקים?",options:["DNS","Provisioner פועל? בדוק Events של PVC","RBAC","kubectl restart"],answer:1,explanation:"PVC Pending עם StorageClass = Provisioner לא צליח ליצור PV. kubectl describe pvc יציג Events.\nבדוק: provisioner pod רץ? Permissions? Disk quota?"},
    {q:"ה-PV עם Reclaim Policy=Retain. PVC נמחקת. מה קורה ל-PV?",options:["PV נמחק אוטומטית","PV נשאר ב-Released – נתונים שמורים אבל PVC חדשה לא יכולה לקשור","PV מאופס","PV משויך ל-PVC הבאה"],answer:1,explanation:"Retain: PV לא נמחק ולא מנוקה.\nעובר ל-Released.\nלשימוש חוזר: מחק claimRef ידנית.\nDelete: PV נמחק עם ה-PVC.\nRecycle: מיושן."},
    {q:"ה-StorageClass לא קיימת. PVC מפנה אליה. מה הסטטוס?",options:["PVC נוצרת עם storage ברירת מחדל","PVC נשארת Pending עם 'storageclass not found'","PVC נמחקת","PV נוצר"],answer:1,explanation:"אם StorageClass לא קיימת, PVC תישאר Pending. kubectl describe pvc יציג: 'storageclass not found'.\nבדוק שם StorageClass נכון."},
    {q:"ה-Pod מנסה לכתוב ל-volume ומקבל Permission denied. UID=1000. מה בודקים?",options:["DNS","fsGroup ב-securityContext – קובע ownership של הvolume","RBAC","StorageClass"],answer:1,explanation:"Pod securityContext.fsGroup קובע ש-volume יהיה owned על ידי GID זה.\nאם לא מוגדר והvolume owned על ידי root, UID 1000 לא יכול לכתוב."},
    {q:"ה-PVC עם accessMode=ReadWriteOnce. שני Pods מנסים mount. מה קורה?",options:["שניהם מקבלים גישה","Pod שני נשאר Pending – RWO מאפשר mount על Node אחד בלבד","שגיאת DNS","Eviction"],answer:1,explanation:"ReadWriteOnce: volume ניתן לmount כ-ReadWrite על Node אחד בלבד.\nPod שני על Node אחר יישאר Pending.\nRWX מאפשר mount על מספר Nodes."},
    {q:"כיצד מגדילים PVC קיימת?",options:["אי אפשר להגדיל PVC","StorageClass עם allowVolumeExpansion:true + patch PVC עם גודל חדש","מוחקים ומוצרים מחדש","יש לפרמט מחדש"],answer:1,explanation:"הגדלת PVC: (1) StorageClass.allowVolumeExpansion:true, (2) kubectl patch pvc עם גודל חדש.\nהגדלה online אפשרית ברוב CSI drivers; צמצום לא נתמך."},
    {q:"אחסון emptyDir מול hostPath – מה ההבדל העיקרי?",options:["אין הבדל","emptyDir: חי כל עוד Pod חי, לא persist; hostPath: mount מ-Node FS, נשאר אחרי restart","hostPath מאובטח יותר","emptyDir גדול יותר"],answer:1,explanation:"emptyDir: נוצר ריק, נמחק עם Pod. hostPath: מוסר directory מ-Node ישירות, מסוכן ב-production.\nלshared temp storage בין containers – emptyDir."},
    {q:"ה-StatefulSet עם volumeClaimTemplate. Pod-0 נמחק ונוצר מחדש. מה קורה ל-PVC שלו?",options:["PVC נמחקת","PVC נשמרת – Pod-0 החדש מתחבר לאותה PVC","PVC חדשה נוצרת","נתונים אובדים"],answer:1,explanation:"PVCs של StatefulSet נשמרות בשם קבוע ולא נמחקות עם Pod.\nPod חדש מתחבר לאותה PVC עם אותם נתונים."},
    {q:"תהליך Dynamic provisioning לא עובד. kubectl describe pvc מציג 'waiting for volume'. מה הסיבה?",options:["RBAC","Provisioner pod לא פועל, StorageClass שגוי, או quota הגיעה","DNS","Ingress"],answer:1,explanation:"dynamic provisioning דורש: (1) StorageClass עם provisioner מוגדר, (2) Provisioner pod פועל, (3) Permissions לprovisioner, (4) cloud quota לא מוצה."},
    {q:"תהליך Volume Snapshot דורש מה?",options:["רק StorageClass","VolumeSnapshotClass + CSI driver שתומך ב-snapshots","kubectl version ספציפי","RBAC בלבד"],answer:1,explanation:"Volume Snapshots דורשים: (1) CSI driver עם snapshot capability, (2) VolumeSnapshotClass, (3) external-snapshotter controller.\nלא כל CSI drivers תומכים."},
    {q:"שרת NFS volume לא עולה: 'mount.nfs: Connection refused'. מה בודקים?",options:["kubelet","NFS server זמין? firewall port 2049? NFS exports מוגדר?","RBAC","imagePullSecret"],answer:1,explanation:"בעיות NFS: (1) NFS server לא פועל, (2) port 2049 חסום, (3) /etc/exports לא כולל IP של Node, (4) nfs-utils לא מותקן.\nבדוק לפי הסדר."},
    {q:"ה-PV נוצר עם capacity=10Gi. PVC מבקשת 5Gi. יש binding?",options:["לא – גודל חייב להיות זהה","כן – PV עם גודל גדול יותר יכול לתת לPVC עם דרישה קטנה יותר","PVC מקבלת 10Gi","PV מצטמצם ל-5Gi"],answer:1,explanation:"PVC binding: K8s מחפש PV שעומד בדרישות (accessMode, storageClass, גודל >= מה שמבוקש).\nPV של 10Gi יכול לתת לPVC של 5Gi."},
    // ── Troubleshooting extra ──
    {q:"ה-Node בסטטוס NotReady. מה הצעד הראשון?",options:["kubectl delete node","kubectl describe node + ssh לNode + systemctl status kubelet","מחק כל ה-Pods","scale down"],answer:1,explanation:"NotReady = kubelet לא מדווח.\nבדוק: (1) kubectl describe node לConditions, (2) ssh לNode, (3) systemctl status kubelet, (4) journalctl -u kubelet -n 50."},
    {q:"הפקודה kubectl exec -it pod -- /bin/bash מחזיר 'OCI runtime exec failed'. מה הסיבה?",options:["RBAC חסום","bash לא קיים ב-image (distroless) – נסה /bin/sh","DNS","StorageClass"],answer:1,explanation:"Images כמו distroless לא כוללים bash.\nנסה: /bin/sh.\nאם גם sh לא קיים: kubectl debug -it pod --image=busybox."},
    {q:"ה-Pod restartCount=47. מה זה מסמל?",options:["Pod בריא","Pod קורס שוב ושוב – בדוק logs --previous","Pod ב-upgrade","normal behavior"],answer:1,explanation:"restartCount גבוה = Pod קורס חוזר ונשנה (CrashLoopBackOff).\nבדוק: kubectl logs <pod> --previous לשגיאת האתחול האחרונה."},
    {q:"שרת etcd ב-high disk I/O. cluster איטי. מה ההשפעה?",options:["רק Pods מושפעים","API server איטי – etcd backend לכל אובייקטי K8s; latency גבוה מאט control plane","DNS נכשל","Nodes לא מדווחים"],answer:1,explanation:"etcd הוא ה-brain של K8s.\nכל kubectl apply/get עוברים דרך API server → etcd. disk latency מאט את כל control plane.\nפתרון: SSD, הפחתת watch connections, etcd defrag."},
    {q:"הפקודה kubectl get pods: 'the server is currently unable to handle the request'. מה הסיבה?",options:["Pod קרס","API server rate limiting – יותר מדי requests","DNS","CNI"],answer:1,explanation:"API server מגביל requests כדי למנוע עומס.\nגורמים: controllers, kubectl watch loops, CI/CD שמריץ kubectl כל שניה.\nבדוק kube-apiserver metrics."},
    {q:"שכבת ה-Container runtime (containerd) לא מגיב על Node. מה לא יעבוד?",options:["רק Pods חדשים","ניהול containers לא אפשרי – לא exec, לא logs חדשים, לא Pods חדשים","DNS בלבד","Ingress בלבד"],answer:1,explanation:"kubelet מתקשר עם container runtime דרך CRI.\nללא runtime: לא ניתן להפעיל containers, לבצע exec, לקחת logs.\nPods קיימים ממשיכים לרוץ בhardware."},
    {q:"שירות ה-kubelet certificate פג. מה קורה?",options:["kubelet עוצר","Node עובר ל-NotReady – TLS handshake נכשל מול API server","Pod רץ בכל מקרה","RBAC שגיאה"],answer:1,explanation:"kubelet מתחבר ל-API server עם client certificate.\nCertificate שפג → TLS handshake נכשל → Node NotReady.\nפתרון: Certificate Rotation (--rotate-certificates)."},
    {q:"ה-CoreDNS Pods קרסו. מה הסימפטום?",options:["Nodes NotReady","DNS פנימי לא עובד – Pods לא מצליחים לפתור שמות services","kubectl לא עובד","Ingress נכשל"],answer:1,explanation:"CoreDNS מספק service discovery.\nללא CoreDNS, Pods לא יכולים לפתור <service>.<namespace>.svc.cluster.local ואפליקציות ייכשלו."},
    {q:"ה-cluster upgrade נכשל. מה הדרך הבטוחה לrollback?",options:["kubectl rollback","etcd restore מbackup לפני ה-upgrade","downgrade kubelet","מחק control plane"],answer:1,explanation:"לrollback של K8s cluster: היחידה הדרך האמינה היא etcd snapshot restore.\nחובה לצלם etcd snapshot לפני כל upgrade."},
    {q:"הפקודה kubectl top nodes מחזיר 'Metrics API not available'. מה הסיבה?",options:["kubectl גרסה ישנה","metrics-server לא מותקן","RBAC","etcd"],answer:1,explanation:"kubectl top מסתמך על Metrics Server.\nאם לא מותקן, ה-API v1beta1.metrics.k8s.io לא קיים.\nבדוק: kubectl get apiservice | grep metrics."},
    {q:"ה-Pod לא רואה env vars מ-Secret שנוצר אחרי ה-Pod. מה קורה?",options:["Pod מתעדכן אוטומטית","Secret כ-env var נטען רק בזמן startup – Pod ישן לא יראה Secret חדש","Secret מתפשט אוטומטית","RBAC"],answer:1,explanation:"Secrets כ-env vars נטענים רק בcontainer startup.\nשינויים ב-Secret לא מתעדכנים ב-Pod קיים.\nלעדכון: restart את ה-Pod.\nSecret כvolume מתעדכן בתוך דקות."},
    {q:"כיצד בודקים שכל רכיבי ה-control plane בריאים?",options:["kubectl get all","kubectl get componentstatuses ו-kubectl get --raw '/healthz'","docker ps","netstat"],answer:1,explanation:"kubectl get componentstatuses מציג scheduler, controller-manager, etcd.\nכמו כן: kubectl get pods -n kube-system לכל ה-control plane pods.\nב-K8s חדש: kubectl get --raw '/healthz?verbose'."},
    {q:"ה-Pod שיצא עם exit code 137. מה המשמעות?",options:["הצלחה","OOMKilled – הקרנל סיים את הprocess בגלל חריגה ממגבלת זיכרון","Segfault","Container runtime קרס"],answer:1,explanation:"Exit code 137 = 128 + SIGKILL (signal 9).\nבcontainer context, לרוב מציין OOMKilled.\nבדוק: kubectl describe pod לאירוע OOMKilled וגדל את limits.memory."},
    {q:"הפקודה kubectl apply מחזיר 'field is immutable'. מה עושים?",options:["מוסיפים --force","מוחקים ומוצרים מחדש את ה-resource (immutable fields לא ניתנים לשינוי)","kubectl edit","שינוי namespace"],answer:1,explanation:"חלק מfields ב-K8s immutable (כגון spec.selector ב-Service/Deployment).\nלשינויהם חובה: kubectl delete + kubectl apply מחדש."},
    {q:"ה-Pod רץ עם 2 containers. Container ראשון קורס. מה קורה?",options:["שני ה-containers מאותחלים","רק ה-container שקרס מאותחל; ה-Pod ממשיך לרוץ","ה-Pod נמחק","restartPolicy קובע – Always: Container מאותחל בלבד, לא ה-Pod כולו"],answer:3,explanation:"ב-Pod עם מספר containers, כל container מנוהל בנפרד.\nContainer שקורס מאותחל לפי restartPolicy (Always/OnFailure/Never).\nה-Pod עצמו לא נמחק ו-containers אחרים ממשיכים לרוץ."},
  ],

  en: [
    // ── Workloads ──
    {q:"A pod named api-server is in CrashLoopBackOff. What is the first step to diagnose?",options:["kubectl delete pod api-server","kubectl logs api-server --previous","kubectl edit pod api-server","kubectl drain node"],answer:1,explanation:"--previous shows logs from the last crashed run.\nThis is always the first step for CrashLoopBackOff - the logs will reveal the startup error."},
    {q:"A pod stays Pending. kubectl describe shows '0/3 nodes available: 3 Insufficient memory'. What is the correct solution?",options:["Restart the pod","Change namespace","Lower the pod's memory requests or add a Node to the cluster","Delete other pods"],answer:2,explanation:"The Scheduler can't find a Node with enough free memory to cover the requests.\nLower the pod's memory requirements or add a Node with available memory."},
    {q:"A rolling update is stuck - a new pod is created but never reaches Ready. What is the most common cause?",options:["Image does not exist in repo","The readiness probe is failing on the new pod","No DNS","Missing RBAC"],answer:1,explanation:"When a rollout stalls, the most common reason is a failing readiness probe - Kubernetes waits for the pod to become Ready before updating more pods."},
    {q:"A pod crashed with OOMKilled. What does this mean and what is the next step?",options:["Network issue - check NetworkPolicy","The kernel killed the container because it exceeded its memory limit - increase limits.memory","Corrupt image - repull","CPU throttling - increase CPU"],answer:1,explanation:"OOMKilled = Out Of Memory Killed.\nThe kernel terminated the container because it exceeded the memory limit.\nIncrease limits.memory or investigate a memory leak in the application."},
    {q:"An HPA is configured for a Deployment but doesn't scale despite high CPU. What is the most likely cause?",options:["No Ingress","metrics-server is not installed or not running","maxReplicas is too low","Wrong namespace"],answer:1,explanation:"HPA depends on metrics-server to read CPU/memory metrics.\nWithout metrics-server, HPA can't get the data it needs to make scaling decisions."},
    {q:"An init container fails every attempt with exit code 1 and logs show 'connection refused'. What do you check?",options:["resource limits of the init container","Whether the service the init container is waiting for is actually up and running","Wrong image tag","Wrong namespace"],answer:1,explanation:"Init containers are often used to wait for a dependency. 'connection refused' means the target isn't available.\nVerify the dependency service is running before the pod starts."},
    {q:"A Deployment tries to run 5 replicas but only 3 start. kubectl describe shows 'pod didn't trigger scale-up'. What do you check?",options:["Cluster autoscaler not configured or nodes can't scale out","Wrong image","Missing secrets","Namespace quota"],answer:0,explanation:"When pods can't be scheduled, the Cluster Autoscaler should add nodes.\nIf it doesn't - check that autoscaling is configured, no quota is full, and cloud instances are available."},
    {q:"A Job runs but never completes. kubectl get job shows COMPLETIONS 0/1 after an hour. What do you investigate?",options:["Delete the job and recreate it","kubectl logs of the Job's pod - the process is likely stuck","kubectl describe node","Change restartPolicy"],answer:1,explanation:"A job that never finishes usually has a stuck process.\nCheck the pod logs to see if it's a deadlock, waiting for input, or an infinite loop."},
    {q:"A pod shows READY 0/1 but STATUS Running. The application inside is working. What is wrong?",options:["Liveness probe failing","Readiness probe failing - the pod won't receive traffic","Wrong image","Low resource limits"],answer:1,explanation:"0/1 Ready means the readiness probe is failing.\nThe pod runs but won't receive traffic from the Service.\nCheck the readiness probe path and port configuration."},
    {q:"A StatefulSet database-0 crashed and won't restart. kubectl describe shows 'volume is already exclusively attached'. What happened?",options:["Missing image","PVC with ReadWriteOnce is attached to another node - node drain was not completed cleanly","Wrong namespace","Missing RBAC"],answer:1,explanation:"ReadWriteOnce allows attachment to only one node at a time.\nIf the previous node didn't fully release the volume (e.g. after a crash), the new pod can't attach it.\nWait for the node to detach or force a detach."},

    // ── Networking ──
    {q:"kubectl get endpoints my-svc shows '<none>'. The Service exists and pods are running. What is the issue?",options:["Missing Ingress","The Service selector doesn't match the pod labels","Missing NodePort","Missing NetworkPolicy"],answer:1,explanation:"Empty endpoints almost always mean a selector mismatch between the Service and its pods.\nCheck with kubectl get pods --show-labels."},
    {q:"A pod can't reach another service inside the cluster. curl http://my-svc.default.svc.cluster.local returns 'Could not resolve host'. What do you check?",options:["NetworkPolicy","CoreDNS pods in kube-system - are they running and healthy?","Ingress","Service type"],answer:1,explanation:"A DNS resolution failure inside the cluster points to CoreDNS.\nCheck: kubectl get pods -n kube-system | grep coredns and verify they are Running and Ready."},
    {q:"An Ingress is configured and DNS resolves correctly, but all requests return 404. What do you check?",options:["TLS certificate","The Ingress path rule doesn't match the path the application listens on","Ingress namespace","Pod image"],answer:1,explanation:"A 404 from Ingress usually means a path mismatch.\nIf the app listens on / but the Ingress defines path: /api, requests won't match.\nCheck path and pathType."},
    {q:"A NetworkPolicy was applied to a namespace. Now Pod A can't talk to Pod B in the same namespace. What happened?",options:["NetworkPolicy in K8s is default-deny - no allow rule was defined between the pods","Pods are in different namespaces","Service missing","DNS failure"],answer:0,explanation:"NetworkPolicy in Kubernetes is an additive allow-list.\nWhen a policy is applied, all traffic not explicitly allowed is blocked.\nAdd an ingress rule that permits communication within the namespace."},
    {q:"A LoadBalancer Service stays in Pending (EXTERNAL-IP <pending>) on a local single-node cluster. Why?",options:["Missing Ingress","LoadBalancer requires a cloud provider integration - not available in local clusters without tools like MetalLB","Missing DNS","Missing TLS"],answer:1,explanation:"LoadBalancer type relies on a cloud provider (AWS, GCP, Azure) to allocate an external IP.\nOn local clusters (minikube, kind) this isn't available without MetalLB or similar.\nUse NodePort for local testing."},
    {q:"Pod A can't reach the internet. curl google.com fails, but another pod in the same namespace succeeds. What do you check?",options:["kubectl logs","NetworkPolicy egress rule on the specific pod that blocks outbound traffic","Wrong image","DNS"],answer:1,explanation:"If one pod can't reach the outside but others can, a NetworkPolicy with egress restrictions on that pod's labels is the prime suspect.\nCheck policies applied by label."},
    {q:"A ClusterIP Service is reachable from inside pods, but the NodePort on port 30080 isn't reachable from outside the cluster. What is the likely cause?",options:["Firewall / security group is blocking port 30080","Missing Ingress","Wrong DNS","RBAC"],answer:0,explanation:"NodePort opens a port on all nodes, but an external firewall (security groups, iptables) may block it.\nEnsure port 30080 is open in the security group and that no iptables rule is blocking it."},

    // ── Config & Security ──
    {q:"A pod fails to access a Secret you created. kubectl describe pod shows 'secret not found'. What do you check?",options:["RBAC","Whether the Secret is in the same namespace as the pod","Secret encryption","Image pull"],answer:1,explanation:"Secrets and pods must be in the same namespace.\nA Secret in namespace A is not accessible to a pod in namespace B.\nVerify the Secret was created in the correct namespace."},
    {q:"A ServiceAccount tries to run kubectl get pods and gets 'Forbidden'. A Role exists. What is missing?",options:["Increase resource limits","A RoleBinding that connects the Role to the ServiceAccount","ClusterRole","Secret"],answer:1,explanation:"A Role alone is not enough.\nA RoleBinding is required to connect the Role (permissions) to the Subject (ServiceAccount).\nWithout a RoleBinding the Role has no effect."},
    {q:"A ConfigMap was updated with new values, but the app in the pod still sees old values. Why?",options:["ConfigMap is invalid","Most apps read ConfigMaps once at startup - the pod needs a restart","RBAC blocked the ConfigMap","Wrong namespace"],answer:1,explanation:"When a ConfigMap is injected as env vars, changes only take effect after a pod restart.\nAs a volume, updates propagate within a few minutes - but the app must re-read the file."},
    {q:"A pod tries to pull from a private Docker registry and gets ImagePullBackOff. What is missing?",options:["Resource limits","imagePullSecrets is not set on the pod spec - the Secret with registry credentials is missing","NetworkPolicy","Node taints"],answer:1,explanation:"To pull from a private registry, the pod needs imagePullSecrets referencing a Secret of type kubernetes.io/dockerconfigjson with registry credentials."},
    {q:"A pod tries to run as root (uid 0) but is rejected. What is the likely reason?",options:["Missing NetworkPolicy","PodSecurityAdmission or PodSecurityPolicy has runAsNonRoot: true configured","Missing PVC","Missing Service"],answer:1,explanation:"Pod Security Admission can block containers from running as root.\nIf the namespace has a restricted or baseline policy, pods requesting root will be rejected.\nChange securityContext.runAsUser."},
    {q:"A Secret is mounted as an env var: value = 'dXNlcjpwYXNz'. The app receives this string instead of 'user:pass'. What is wrong?",options:["Wrong secret type","Kubernetes decodes Secrets from base64 automatically - if the Secret was created with an already base64-encoded value, the pod receives double-encoded data","RBAC","Wrong namespace"],answer:1,explanation:"Kubernetes automatically decodes Secret values from base64 when injecting into pods.\nIf the Secret was created with an already-encoded value, the pod receives base64 instead of the plaintext.\nCreate the Secret with the raw value."},

    // ── Storage ──
    {q:"A PVC is Pending. kubectl describe pvc shows 'storageclass.storage.k8s.io not found'. What is the issue?",options:["Missing namespace","The StorageClass specified in the PVC does not exist - check with kubectl get storageclass","PV is full","Missing secret"],answer:1,explanation:"The PVC references a StorageClass that doesn't exist.\nVerify that the storageClassName in the PVC matches one of the existing StorageClasses (kubectl get storageclass)."},
    {q:"Two pods try to mount the same PVC. The second pod stays Pending with 'Multi-Attach error'. Why?",options:["Missing NetworkPolicy","PVC with accessMode ReadWriteOnce (RWO) can only be attached to one node at a time","Missing secret","Resource limits"],answer:1,explanation:"ReadWriteOnce means the volume can only be mounted to one node at a time.\nIf two pods on different nodes try to attach it, the second is blocked.\nFix: change to ReadWriteMany if the storage backend supports it."},
    {q:"A helm upgrade fails with 'cannot patch because a resource with that name already exists (not managed by Helm)'. What happened?",options:["Wrong values.yaml","A resource was manually created outside Helm so Helm doesn't manage it - use helm upgrade --force or delete it manually","Wrong namespace","Wrong image"],answer:1,explanation:"Helm tracks resources it created.\nIf a resource was manually created with the same name, Helm can't manage it.\nYou can annotate the resource as managed by Helm or delete it and let Helm recreate it."},
    {q:"A PV was deleted while a PVC still existed. The PVC is now in 'Lost' status. What do you do?",options:["Delete the PVC and wait","Create a new PV with a claimRef pointing to the existing PVC","kubectl restart pvc","Delete namespace"],answer:1,explanation:"When a PV is deleted the PVC enters Lost status.\nCreate a new PV with spec.claimRef referencing the namespace/name of the existing PVC to restore the binding."},
    {q:"A pod tries to write to a volume but gets 'Read-only file system'. A PVC is defined in the YAML. What do you check?",options:["ReadWriteOnce accessMode doesn't support writes","volumeMounts.readOnly: true is set on the pod spec - remove it","Wrong image","Missing Secret"],answer:1,explanation:"If volumeMounts has readOnly: true, the container cannot write to the volume even if the PVC allows it.\nRemove readOnly: true from volumeMounts."},

    // ── Troubleshooting ──
    {q:"A node suddenly changes to NotReady. What is the first diagnostic step?",options:["Delete all pods on the node","kubectl describe node and SSH to the node to check kubelet logs","kubectl delete node","Roll back the cluster"],answer:1,explanation:"kubectl describe node shows conditions (DiskPressure, MemoryPressure, NetworkUnavailable).\nThen SSH to the node and run: systemctl status kubelet to get details on why kubelet stopped reporting."},
    {q:"A pod has been stuck in Terminating for 30 minutes. kubectl delete doesn't help. What do you do?",options:["chmod on the pod","kubectl delete pod <name> --force --grace-period=0","kubectl restart pod","Wait an hour"],answer:1,explanation:"A stuck Terminating pod usually has a finalizer that hasn't completed. --force --grace-period=0 forces immediate deletion.\nUse with caution in production."},
    {q:"kubectl exec fails: 'error: unable to upgrade connection: container not found'. What is the reason?",options:["Missing RBAC","The container has already exited - the pod is likely in CrashLoop","Wrong image","Node issue"],answer:1,explanation:"kubectl exec opens a connection to a running container.\nIf the container has exited (CrashLoop), there is no container to exec into.\nCheck logs and fix the crash cause."},
    {q:"The cluster autoscaler is not adding nodes despite pods being Pending. What do you check?",options:["kubectl get pods","Logs of the cluster-autoscaler pod - possible taint/toleration mismatch, quota hit, or no available instance type","kubectl describe node","DNS"],answer:1,explanation:"The autoscaler adds nodes only if it determines new pods could run on the new node.\nIf there's an unmatched taint, a full quota, or a cloud provider issue, it won't add nodes."},
    {q:"A node is showing DiskPressure. Pods start getting evicted. What is the quick fix?",options:["Create a PVC","Clean up images, logs, and temp files on the node - docker system prune","Increase memory limits","Change namespace"],answer:1,explanation:"DiskPressure occurs when the node's disk fills up.\nQuick fix: SSH to the node, prune unused images (docker/crictl image prune) and old logs.\nLong-term: expand disk or implement log rotation."},
    {q:"kubectl top nodes fails: 'error: Metrics API not available'. What is missing?",options:["RBAC","metrics-server is not installed in the cluster","DNS","StorageClass"],answer:1,explanation:"kubectl top requires metrics-server which provides CPU/memory metrics.\nWithout it, HPA won't work either.\nInstall: kubectl apply -f https://github.com/kubernetes-sigs/metrics-server/releases/latest/download/components.yaml"},
    {q:"kubectl drain node1 is blocked: 'cannot delete Pods not managed by ReplicationController, ReplicaSet, Job, DaemonSet, or StatefulSet'. What do you do?",options:["kubectl delete node","Add --force --ignore-daemonsets","kubectl uncordon","Create a PDB"],answer:1,explanation:"kubectl drain is blocked by standalone pods (without a controller). --force allows deleting them. --ignore-daemonsets skips DaemonSet pods that can't be moved."},
    {q:"A liveness probe on path /healthz is failing every 30 seconds, causing the container to restart. The app is actually working. What do you check?",options:["Resource limits","The liveness probe is hitting the wrong port or path, or the response is not a 2xx/3xx status","Wrong image","NetworkPolicy"],answer:1,explanation:"If the app works but the liveness probe fails, the probe is likely misconfigured - wrong port, wrong path, or the health endpoint returns a non-success status.\nVerify the path and port match the app's health endpoint."},
    {q:"After kubectl rollout undo, the Deployment reverted but the app is still broken. What do you check?",options:["kubectl delete deployment","The undo may have reverted to a revision that was also broken - check rollout history and select a specific revision","kubectl get nodes","DNS"],answer:1,explanation:"kubectl rollout undo reverts to the previous revision, but if that was also broken it won't help.\nUse kubectl rollout history deployment/my-app to see all revisions, then rollout undo --to-revision=N."},
    {q:"kubectl apply -f manifest.yaml succeeds with no error, but the resource is not created where expected. What do you check?",options:["kubectl delete namespace","kubectl get events and check the namespace - the resource may have been created in the wrong namespace","RBAC","Image"],answer:1,explanation:"apply succeeds at the API level but the resource is created in the namespace defined in the YAML (which may be wrong) or in default.\nCheck: kubectl get <resource> --all-namespaces."},
    {q:"A new pod can't be scheduled on any node. kubectl describe pod shows Taints. What is the fix?",options:["Delete the pod","Add a toleration to the pod spec that matches the node taint","Increase CPU","Change namespace"],answer:1,explanation:"When a node has a taint, only pods with a matching toleration can run on it.\nAdd a tolerations entry to the pod spec that matches the taint (key, operator, effect)."},
    {q:"An etcd pod in kube-system is showing issues. How many etcd members should a healthy production cluster have?",options:["1","2","3 (or any odd number)","Exactly 5"],answer:2,explanation:"etcd requires quorum - a majority of members must be available. 3 members tolerate 1 failure; 5 tolerate 2.\nAlways use an odd number to prevent split-brain.\nProduction typically uses 3 or 5."},
    {q:"A namespace is stuck in Terminating for over an hour. What is the most likely cause?",options:["No RBAC","Finalizers on resources inside the namespace are preventing deletion","DNS failure","etcd issue"],answer:1,explanation:"A namespace stuck in Terminating is almost always blocked by finalizers that haven't been cleared.\nIdentify resources with finalizers (often CRDs) and remove them manually or patch the namespace to remove the finalizers."},
    {q:"A pod is running on node1. kubectl drain node1 is executed. What happens next?",options:["The pod is immediately live-migrated by Kubernetes","drain terminates the pod; the owning controller (Deployment) creates a new pod that the Scheduler places on another node","The pod cannot move nodes","One hour later"],answer:1,explanation:"kubectl drain terminates pods on the node.\nThe Deployment controller notices the missing replica and creates a new pod, which the Scheduler places on a non-cordoned node."},
    {q:"RBAC is configured with a ClusterRole but you only want it to apply to a specific namespace. Which binding do you use?",options:["ClusterRoleBinding only","RoleBinding - allows using a ClusterRole but scopes permissions to the namespace of the RoleBinding","Role","ServiceAccount"],answer:1,explanation:"A RoleBinding can reference a ClusterRole, but it restricts the permissions to the namespace where the RoleBinding lives.\nClusterRoleBinding grants cluster-wide access.\nFor scoped access use a RoleBinding pointing to a ClusterRole."},
    {q:"A pod in namespace prod tries to access a ConfigMap from namespace staging. What happens?",options:["It works automatically","Pods cannot directly access resources in other namespaces","A ClusterRole is needed","A NetworkPolicy is needed"],answer:1,explanation:"Pods access ConfigMaps, Secrets, and other resources only within their own namespace.\nTo share data across namespaces, duplicate the resource or use an external config store."},
    {q:"A readinessGate is defined on a pod. The pod shows READY 0/1 even though the readiness probe passes. What do you check?",options:["Liveness probe","The readinessGate condition is not satisfied - it is set by an external controller (e.g. load balancer sync)","Image","DNS"],answer:1,explanation:"ReadinessGates let external controllers determine pod readiness.\nThe pod is only Ready after the additional condition (e.g. network LB sync) is set to True in pod status.\nCheck the custom conditions."},
    {q:"You apply a PodDisruptionBudget. kubectl drain fails: 'Cannot evict pod as it would violate the pod disruption budget'. What happened?",options:["Node issue","PDB defines minAvailable=2 but only 2 pods exist - drain would reduce below the minimum","StorageClass issue","NetworkPolicy"],answer:1,explanation:"PDB defines how many pods must remain available.\nIf drain would reduce the count below minAvailable, it is blocked.\nFix: ensure enough replicas exist before draining, or temporarily scale up the Deployment."},
    {q:"While debugging, you run kubectl exec pod -- env and see SECRET_KEY is missing. What do you check?",options:["RBAC","Whether the Secret exists in the namespace and whether valueFrom.secretKeyRef is correct in the pod YAML","DNS","NetworkPolicy"],answer:1,explanation:"When a Secret-sourced env var is missing, check: the Secret exists, secretName is correct, key is correct, and namespace matches.\nUse kubectl get secret <name> -n <namespace> and kubectl describe pod."},
    {q:"Pod A tries to reach Pod B on port 8080 and gets a connection timeout (not refused). No NetworkPolicy is configured. What do you check?",options:["Pod B is not listening on port 8080 - the process may not have started","RBAC","StorageClass","Ingress"],answer:0,explanation:"Without NetworkPolicy, traffic is only restricted by the process itself.\nTimeout (not refused) suggests the port is filtered at the network level, or Pod B isn't listening.\nCheck: kubectl exec podB -- netstat -tlnp."},
    {q:"A Deployment with 3 replicas has all pods in ImagePullBackOff. kubectl describe shows 'Back-off pulling image'. What is the first step?",options:["Delete the Deployment","Check the image tag in the YAML - does the tag exist in the registry?","kubectl get nodes","Check etcd"],answer:1,explanation:"ImagePullBackOff means the image can't be pulled.\nCommon causes: tag doesn't exist, wrong image name, or missing imagePullSecrets for a private registry. kubectl describe pod shows the exact image name being requested."},
    {q:"You want pods to be spread across availability zones for HA. What is the best approach?",options:["Node affinity only","topologySpreadConstraints with topologyKey: topology.kubernetes.io/zone","DaemonSet","StatefulSet"],answer:1,explanation:"topologySpreadConstraints spread pods evenly across zones (or nodes, racks).\nConfigure maxSkew and topologyKey for zone.\nThis is preferred over pod anti-affinity as it is more flexible and scalable."},
    {q:"A pod is in CrashLoop. Logs show 'permission denied' on path /data. What is the issue?",options:["Missing PVC","The container runs as a user that lacks write permission to /data - check securityContext.runAsUser and fsGroup","Wrong image","Namespace"],answer:1,explanation:"When a process inside a container can't write to a path, check securityContext.\nSolutions: set fsGroup so the group owns the mounted volume, fix ownership in the Dockerfile, or run as a user with appropriate permissions."},
    {q:"A namespace has a ResourceQuota of requests.cpu=2. A new pod requests cpu: 4. What happens?",options:["Pod gets 2 cpu","Pod is rejected - it exceeds the quota","Pod gets 4 cpu","Pod stays Pending"],answer:1,explanation:"ResourceQuota enforces resource consumption limits per namespace.\nA pod requesting more than the remaining quota is rejected at creation time with a 403 error."},
    {q:"A LimitRange in a namespace sets a default cpu limit of 500m. A pod is created with no cpu limit. What is the pod's cpu limit?",options:["No limit","500m from the LimitRange","1 core","Unlimited"],answer:1,explanation:"LimitRange provides default values for resources.\nA pod created without limits automatically receives the LimitRange defaults for that namespace."},
    {q:"A DaemonSet is defined but not running on a newly added node. What is the most likely reason?",options:["DaemonSet needs restart","The node has a taint the DaemonSet has no toleration for","Wrong image","Wrong namespace"],answer:1,explanation:"DaemonSets run a pod on every node unless the node has a taint that the DaemonSet doesn't tolerate.\nAdd the appropriate toleration to the DaemonSet spec."},
    {q:"You want pods of service A to never run on the same node as pods of service B. What do you configure?",options:["nodeSelector","Pod anti-affinity with topologyKey: kubernetes.io/hostname","NetworkPolicy","ResourceQuota"],answer:1,explanation:"Pod anti-affinity with topologyKey: kubernetes.io/hostname ensures pods with certain labels don't share a node.\nUseful for HA and workload separation."},
    {q:"An HPA is set min=2 max=10 targetCPU=50%. 2 pods are at 80% CPU. How many pods after scale-up?",options:["10","4","3","2"],answer:1,explanation:"HPA formula: ceil(currentReplicas × actual/target) = ceil(2 × 80/50) = ceil(3.2) = 4 replicas.\nScale-up is gradual, not a jump to maximum."},
    {q:"kubectl rollout pause deployment/my-app - what does this do?",options:["Stops all pods","Suspends rollout updates - further spec changes won't trigger a rollout until resume","Deletes the Deployment","Scales to 0"],answer:1,explanation:"rollout pause lets you batch multiple Deployment spec changes and apply them all at once with rollout resume.\nUseful for canary testing and multi-step changes."},
    {q:"A pod exited with code 137. What does this mean?",options:["Success (0)","The container received SIGKILL - typically OOMKill","The container received SIGTERM","Network error"],answer:1,explanation:"Exit code 137 = 128+9 (SIGKILL).\nCommon causes: OOMKilled (kernel killed for exceeding memory limit) or kubectl delete --force.\nCheck kubectl describe pod to confirm."},
    {q:"A multi-container pod needs both containers to share files. What is the standard solution?",options:["A separate PVC","An emptyDir volume mounted by both containers","A ConfigMap","NetworkPolicy"],answer:1,explanation:"emptyDir is created with the pod and deleted with it.\nBoth containers can mount it at different paths to share files.\nThis is the standard solution for intra-pod shared storage."},
    {q:"A pod mounts a hostPath volume at /var/run/docker.sock. What is the security risk?",options:["No risk","The container gains access to the Node's Docker daemon - full container escape is possible","Read-only access only","Performance degradation"],answer:1,explanation:"Mounting docker.sock lets a container spawn containers on the host, read secrets, and escape the container sandbox entirely.\nThis is a classic container escape vector and must be avoided in production."},
    {q:"An emptyDir volume is configured with medium: Memory. How does it differ from a regular emptyDir?",options:["Data persists after restart","Data is stored in RAM (tmpfs) - faster but consumes pod memory","Size scales automatically","Data is stored in etcd"],answer:1,explanation:"emptyDir medium: Memory creates a tmpfs (RAM-based filesystem).\nVery fast for high-throughput I/O but counts against the pod's memory budget.\nData is lost when the pod terminates."},
    {q:"PodSecurityAdmission is set to enforce=restricted on a namespace. A pod tries to run in privileged mode. What happens?",options:["Pod runs privileged","Pod is rejected at admission","Pod runs in reduced mode","RBAC blocks it"],answer:1,explanation:"The restricted policy forbids privileged containers, hostPath volumes, and running as root.\nThe pod is rejected before creation by the admission controller."},
    {q:"A pod has terminationGracePeriodSeconds: 0. What happens when it is deleted?",options:["Pod waits 30 seconds","SIGKILL is sent immediately - no cleanup time","Pod keeps running","SIGTERM then SIGKILL after 1 second"],answer:1,explanation:"terminationGracePeriodSeconds: 0 causes Kubernetes to send SIGKILL immediately, skipping SIGTERM.\nThe process has no time to clean up.\nUse only in test environments."},
    {q:"A Deployment uses strategy: Recreate. What happens during an upgrade?",options:["Rolling update - one pod at a time","All old pods are terminated first, then new ones are created - causes downtime","No change","Automatic blue/green"],answer:1,explanation:"Recreate strategy causes intentional downtime.\nKubernetes terminates all old pods before creating new ones.\nSuitable when two versions cannot run simultaneously (e.g. single-writer database)."},
    {q:"kubectl apply is run twice on the same Secret YAML with different values. What happens?",options:["Error - Secret already exists","Secret is updated with the new values","A duplicate Secret is created","Nothing"],answer:1,explanation:"kubectl apply is declarative - if the resource exists it is updated to match the new YAML.\nUnlike create which fails if the resource exists.\nExisting running pods are not affected."},
    {q:"An Ingress Controller is not installed. An Ingress object is created. What happens?",options:["Ingress works via kube-proxy","The object is stored in etcd but has no effect - no traffic routing occurs","DNS fails","Pods are deleted"],answer:1,explanation:"An Ingress object is only an API definition.\nWithout an Ingress Controller (nginx, traefik, ALB) to implement it, it does nothing.\nThe controller must be installed first."},
    {q:"A pod needs to know its own name and namespace at runtime. What mechanism do you use?",options:["Manual ConfigMap","Downward API - injects pod metadata as env vars or volume files","Secret","kubectl env inject"],answer:1,explanation:"The Downward API lets a pod read its own metadata (name, namespace, labels, annotations, resource limits) as env vars or files - without any external ConfigMap."},
    {q:"Where is the ServiceAccount token mounted inside a container?",options:["/etc/secrets","/var/run/secrets/kubernetes.io/serviceaccount","/sa/token","/k8s/token"],answer:1,explanation:"Kubernetes mounts the ServiceAccount token at /var/run/secrets/kubernetes.io/serviceaccount/token.\nThe ca.crt and namespace are also there.\nThe app reads the token to authenticate to the API server."},
    {q:"kubectl get pods returns 'The connection to the server was refused'. What is the problem?",options:["No pods exist","The API server is down or kubeconfig points to a wrong endpoint","Wrong namespace","RBAC"],answer:1,explanation:"'connection refused' to the API server means the process isn't listening.\nCauses: API server crashed, wrong kubeconfig endpoint, VPN/network issue.\nCheck: kubectl config view, ping the API server IP."},
    {q:"helm install fails: 'release already exists'. What is the solution?",options:["kubectl delete release","helm upgrade --install <release> <chart> - works whether the release exists or not","kubectl delete namespace","helm delete chart"],answer:1,explanation:"helm install fails if the release already exists. helm upgrade --install handles both cases: upgrade if it exists, install if it doesn't.\nThe go-to solution for CI/CD pipelines."},
    {q:"A ConfigMap is used as env vars. The ConfigMap is deleted. Does the running pod notice?",options:["Pod crashes immediately","Pod keeps running - env vars were injected at creation time","ConfigMap is auto-recreated","Pod restarts"],answer:1,explanation:"Env vars from a ConfigMap are injected at pod creation and stored in the process's memory.\nDeleting the ConfigMap has no effect on a running pod.\nA new pod will fail to start."},
    {q:"A Job has activeDeadlineSeconds: 300. What happens after 5 minutes?",options:["Pod is paused","Pod is marked Failed and terminated","Pod restarts","Nothing"],answer:1,explanation:"activeDeadlineSeconds sets a maximum runtime for a Job.\nAfter the deadline, Kubernetes terminates the pod and marks it Failed.\nUseful to prevent Jobs from running indefinitely."},
    {q:"A rolling update runs two versions simultaneously. What must you ensure?",options:["Version lock","Backward compatibility - DB schema and API responses must work for both versions","Immediate rollback","Nothing"],answer:1,explanation:"During a rolling update both versions run together.\nDB migrations must not be destructive (no dropped columns).\nAPI responses must be compatible with both versions.\nThis is the backward compatibility principle."},
    {q:"A Service of type ExternalName is defined. What does it do?",options:["Opens an external port","Creates a DNS CNAME alias to an external hostname - no proxying","Allows external access to the cluster","Defines a firewall rule"],answer:1,explanation:"ExternalName creates a CNAME DNS record pointing to an external hostname (e.g. my-db.external.com).\nPods access the external service as if it were an internal service, without needing IP addresses."},
    {q:"init containers are listed in sequence. initContainer-2 is waiting. What is the behavior?",options:["Both start in parallel","Kubernetes waits for initContainer-1 to exit 0 before starting initContainer-2","Main container starts immediately","Pod is deleted"],answer:1,explanation:"Init containers run sequentially - one at a time.\nKubernetes waits for each to complete (exit 0) before starting the next.\nOnly after all init containers finish do the main containers start."},
    {q:"A NetworkPolicy has podSelector: {} (empty). What does this select?",options:["No pods","All pods in the namespace","All pods in all namespaces","Syntax error"],answer:1,explanation:"An empty podSelector in a NetworkPolicy selects all pods in the namespace.\nThis differs from namespaceSelector: {} which selects all namespaces.\nImportant distinction for writing policies."},
    {q:"A Kubernetes Secret exceeds 1MiB. What happens?",options:["Created with a warning","Rejected - Kubernetes enforces a 1MiB object size limit","Stored in a separate etcd partition","Automatically split"],answer:1,explanation:"etcd and Kubernetes enforce a ~1MiB limit per object (Secret/ConfigMap).\nFor larger data, use an external secret store (HashiCorp Vault, AWS Secrets Manager) and inject references."},
    {q:"A pod needs access to AWS S3 without storing credentials in Kubernetes. What is the recommended approach?",options:["Secret with Access Key","IRSA (IAM Roles for Service Accounts) - K8s SA mapped to AWS IAM Role","ConfigMap with ARN","hostPath"],answer:1,explanation:"IRSA allows pods to receive temporary AWS credentials via a projected ServiceAccount token.\nNo Secrets, no manual rotation.\nGKE equivalent: Workload Identity.\nAzure: Workload Identity Federation."},
    {q:"A pod in namespace prod needs to reach a service in namespace staging. What DNS name is correct?",options:["my-svc","my-svc.staging","my-svc.staging.svc.cluster.local","staging/my-svc"],answer:2,explanation:"The full K8s DNS name is: <service>.<namespace>.svc.cluster.local.\nTo reach a service in another namespace you must use the FQDN or at minimum <service>.<namespace>."},
    {q:"What is the difference between kubectl cordon and kubectl drain?",options:["They are identical","cordon marks a node unschedulable but doesn't remove existing pods; drain also evicts existing pods","cordon deletes pods","drain cannot be undone"],answer:1,explanation:"cordon: node won't accept new pods, existing pods keep running. drain: cordon + evicts all non-DaemonSet pods.\nUse cordon alone for gradual maintenance without disrupting running workloads."},
    {q:"A VPA is in Auto mode. What does it do?",options:["Adds nodes","Adjusts resource requests/limits and restarts pods as needed","Increases replica count","Does nothing"],answer:1,explanation:"VPA Auto mode calculates resource recommendations and applies them by evicting and recreating pods.\nThis causes brief downtime.\nVPA and HPA are generally not recommended together on the same Deployment."},
    {q:"A CronJob has concurrencyPolicy: Forbid. The previous job is still running when the next is scheduled. What happens?",options:["A new job is always created","The new job is skipped - Forbid prevents concurrent runs","Both jobs run in parallel","CronJob is suspended"],answer:1,explanation:"concurrencyPolicy: Allow (default) - concurrent jobs OK.\nForbid - skip new job if previous still running.\nReplace - delete old job and create new one.\nChoose based on workload requirements."},
    {q:"You want a pod to run on a specific node by hostname. What is the simplest approach?",options:["NetworkPolicy","nodeName: <node-name> in pod spec","nodeSelector","Taint"],answer:1,explanation:"nodeName sends the pod directly to a specific node, bypassing the Scheduler entirely.\nSimple but inflexible.\nFor production, prefer nodeSelector or node affinity which use label-based matching."},
    {q:"A pod needs to access the Kubernetes API from inside the cluster. What is the API server address?",options:["https://kube-apiserver:6443","https://kubernetes.default.svc.cluster.local","http://localhost:8080","https://apiserver:443"],answer:1,explanation:"Inside the cluster, the API server is accessible via the special Service: kubernetes.default.svc.cluster.local:443.\nThis ClusterIP Service is created automatically in the default namespace."},
    {q:"After a kubectl apply, the Deployment doesn't update. The old image is still running. What do you check?",options:["kubectl delete","kubectl rollout history - the image tag may not have changed so K8s sees no diff","kubectl restart","DNS"],answer:1,explanation:"Kubernetes detects changes by hashing the pod template.\nIf the image tag (like 'latest') didn't change, Kubernetes sees no diff and skips the rollout.\nUse a unique tag or image digest (sha256) per build."},
    {q:"A pod QoS class is BestEffort. What happens during memory pressure?",options:["It is never evicted","BestEffort pods are evicted first during memory pressure","They are prioritised","They run on separate nodes"],answer:1,explanation:"Kubernetes defines 3 QoS classes: Guaranteed (requests=limits), Burstable (requests<limits), BestEffort (no requests/limits).\nDuring memory pressure, BestEffort is evicted first, then Burstable, then Guaranteed."},
    {q:"A pod has a CPU limit of 200m but the app needs 500m at peak. What happens?",options:["Pod is deleted","CPU throttling - the container runs slower but is not killed","Pod is restarted","Pod is OOMKilled"],answer:1,explanation:"CPU limit causes throttling, not eviction.\nThe container gets less CPU time and runs slower.\nUnlike memory, exceeding CPU limit does not kill the pod.\nThis is an important distinction."},
    {q:"A ConfigMap is mounted as a volume. Its value is updated. When does the pod see the new value?",options:["Immediately","Within a few minutes (kubelet sync TTL) - no restart needed","Only after pod restart","Only after redeployment"],answer:1,explanation:"When a ConfigMap is mounted as a volume, kubelet syncs changes within about 1-2 minutes.\nThe files in the volume are updated in place.\nHowever, if the app reads the file only at startup it still needs a restart."},
    {q:"kubectl rollout status deployment/my-app is stuck for a long time. What is a common cause to check?",options:["etcd is down","progressDeadlineSeconds exceeded - the new pod never reached Ready","DNS failure","StorageClass"],answer:1,explanation:"progressDeadlineSeconds (default 600s) defines how long Kubernetes waits for a rollout to succeed.\nIf exceeded, the Deployment enters a Failed condition.\nCheck pod events to find why the pod isn't reaching Ready."},
    // ── Workloads extra ──
    {q:"You run kubectl scale deployment/app --replicas=0. What happens?",options:["Deployment is deleted","All pods terminate; the Deployment object is preserved","One pod remains","An error is returned"],answer:1,explanation:"Scaling to 0 terminates all pods but keeps the Deployment and ReplicaSet intact.\nUseful for saving resources in dev environments.\nScale back with --replicas=N."},
    {q:"A pod is stuck in Terminating for 20 minutes. kubectl delete has no effect. What do you do?",options:["Reboot the node","kubectl delete pod <name> --force --grace-period=0 and check for finalizers","Delete the namespace","etcd restore"],answer:1,explanation:"Stuck Terminating is usually caused by a finalizer that hasn't been cleared.\nRemove them with: kubectl patch pod <name> -p '{\"metadata\":{\"finalizers\":null}}'. --force bypasses the graceful period."},
    {q:"An init container is failing repeatedly. What pod status do you see?",options:["Running","Init:CrashLoopBackOff","Pending","Error"],answer:1,explanation:"When an init container crashes repeatedly, the pod shows Init:CrashLoopBackOff.\nDebug with: kubectl logs <pod> -c <init-container-name> --previous."},
    {q:"A StatefulSet has 3 replicas. Pod-1 crashes. What does Kubernetes do?",options:["Deletes all pods and restarts","Restarts only Pod-1; pods 0 and 2 continue running","Creates Pod-3 as replacement","Waits for Pod-0 to crash first"],answer:1,explanation:"StatefulSet manages each pod independently with a stable identity.\nOnly the failed pod is restarted.\nIts PVC is retained and reattached to the new pod."},
    {q:"A DaemonSet is not running on a newly added node. What is likely the cause?",options:["DaemonSets don't support new nodes","The node has a taint the DaemonSet does not tolerate, or it is cordoned","Max pods reached","Namespace misconfiguration"],answer:1,explanation:"If a new node has a Taint that the DaemonSet doesn't tolerate, the pod won't be scheduled.\nCheck: kubectl describe node <name> for Taints.\nAdd a matching toleration to the DaemonSet."},
    {q:"A Job has parallelism=3, completions=9. How many pods run at peak?",options:["9","3","1","6"],answer:1,explanation:"parallelism=3 means at most 3 pods run concurrently. completions=9 defines the success target.\nThe Job runs 3 waves of 3 pods until 9 successful completions."},
    {q:"A pod is Evicted from a node. What is the most common reason?",options:["CPU limit exceeded","Node under memory pressure - kubelet evicts by QoS class","Pod manually deleted","Image not found"],answer:1,explanation:"kubelet watches resource pressure.\nUnder memory pressure it evicts: BestEffort first, Burstable second, Guaranteed last.\nEviction differs from deletion - the controller recreates the pod."},
    {q:"A Deployment has maxUnavailable=0, maxSurge=1. What does this mean for rollouts?",options:["No rollout possible","New pod comes up before old goes down - zero downtime","Old pod is deleted first","No limits"],answer:1,explanation:"maxUnavailable=0: no pod can go down until the new one is Ready. maxSurge=1: one extra pod allowed above desired.\nResult: zero-downtime rolling update - new pod up → old pod down."},
    {q:"A pod has a high priorityClassName. No resources are free. What happens?",options:["Pod waits in Pending","High-priority pod triggers preemption of lower-priority pods","Pod is deleted","priorityClass has no effect"],answer:1,explanation:"Preemption: the Scheduler evicts lower-priority pods to make room for a high-priority pod.\nDefine PriorityClasses carefully to avoid disrupting critical workloads."},
    {q:"A namespace ResourceQuota is exhausted. A new pod is created. What happens?",options:["Pod runs anyway","Pod is rejected with 'exceeded quota' error","Pod waits in Pending","ResourceQuota auto-expands"],answer:1,explanation:"When ResourceQuota is exhausted, the API server rejects new resource creation with an explicit error.\nUse kubectl describe resourcequota -n <ns> to see current usage vs limits."},
    {q:"A LimitRange sets default memory request=256Mi. A pod is created with no memory request. What happens?",options:["Pod is rejected","Pod automatically gets request=256Mi","Pod runs without request","Validation error"],answer:1,explanation:"LimitRange injects default requests/limits into pods that don't specify them.\nThe pod gets the defaults automatically upon creation."},
    {q:"An HPA is not scaling up despite high CPU. What do you check first?",options:["Docker logs","Is metrics-server running? Does kubectl top pods work?","StorageClass","Ingress"],answer:1,explanation:"HPA relies on the Metrics API.\nIf metrics-server is not running, kubectl top returns an error and HPA cannot make scaling decisions.\nCheck: kubectl get apiservice v1beta1.metrics.k8s.io."},
    // ── Networking extra ──
    {q:"A pod tries to reach a ClusterIP Service and gets Connection refused. What do you check?",options:["DNS","kubectl get endpoints <service> - are there any addresses?","MTU","StorageClass"],answer:1,explanation:"Connection refused on a ClusterIP usually means the Service has no Endpoints.\nCheck kubectl get endpoints - if empty, the selector doesn't match any Ready pods."},
    {q:"An Ingress returns 404 for all paths. Pods are up and the Service exists. What is the issue?",options:["TLS certificate","IngressClass not set - the controller ignores the Ingress","Pod error","Wrong namespace"],answer:1,explanation:"Since K8s 1.18, Ingress requires spec.ingressClassName.\nIf it's missing and the controller has no default IngressClass, the Ingress is ignored and all paths return 404."},
    {q:"A NetworkPolicy exists. Pod A can't reach Pod B in the same namespace. What do you check?",options:["Taint","Both egress from A to B AND ingress to B from A must be explicitly allowed","kubectl get nodes","DNS"],answer:1,explanation:"NetworkPolicy is bidirectional.\nYou need: (1) egress from A to B allowed, (2) ingress to B from A allowed.\nThe CNI must support NetworkPolicy (Calico/Cilium yes, basic Flannel - no)."},
    {q:"Service selector: app=backend. The pod has label app=Backend (capital B). What happens?",options:["Service works anyway","Label selectors are case-sensitive - no match, no Endpoints","API error","Pod not created"],answer:1,explanation:"Label selectors are case-sensitive. app=backend ≠ app=Backend.\nThe Service won't point to any pod.\nDiagnose with: kubectl get endpoints <service>."},
    {q:"A pod can't resolve external DNS (example.com). CoreDNS is running. What do you check?",options:["CoreDNS logs and upstream resolver config","Ingress","StorageClass","RBAC"],answer:0,explanation:"CoreDNS resolves external names by forwarding to upstream resolvers.\nIf the upstream is misconfigured in the Corefile, external DNS fails.\nAlso check if a NetworkPolicy blocks outbound UDP 53."},
    {q:"How do you reach a NodePort Service (port 32000) from outside the cluster?",options:["http://service-name:32000","http://<any-node-IP>:32000","http://ClusterIP:32000","http://localhost:32000"],answer:1,explanation:"NodePort opens the port on every node.\nAccess from outside: http://<node-external-ip>:32000.\nFor production use LoadBalancer or Ingress instead."},
    {q:"A pod can't reach the internet. Internal DNS and ClusterIP work. What do you check?",options:["imagePullSecret","Is NAT/masquerade configured? Does a NetworkPolicy block egress?","StorageClass","RBAC"],answer:1,explanation:"Internet access from a pod goes through NAT.\nCheck: (1) kube-proxy/CNI NAT rules, (2) NetworkPolicy egress not blocking 0.0.0.0/0, (3) Node firewall rules."},
    {q:"An Ingress has TLS configured. The browser shows a certificate error. The Secret exists. What do you check?",options:["DNS","Is the Secret in the same namespace as the Ingress? Does the CN/SAN match the domain?","kubelet","etcd"],answer:1,explanation:"A TLS Secret must be in the same namespace as the Ingress.\nThe certificate CN/SAN must match the domain.\nCheck: kubectl describe secret <tls-secret>."},
    {q:"A Service exists but kubectl get endpoints returns empty. What is the cause?",options:["Service in wrong namespace","Pods are not Ready or selector doesn't match","DNS failure","StorageClass"],answer:1,explanation:"Endpoints are created only when there are pods with matching labels that are also Ready.\nCheck: kubectl get pods --show-labels and compare with Service selector."},
    {q:"A Headless Service (clusterIP: None) - what does a DNS lookup on the Service name return?",options:["A single ClusterIP","A list of pod IPs directly","DNS error","Node IP"],answer:1,explanation:"A Headless Service has no ClusterIP.\nDNS returns A records for each pod directly.\nUseful for StatefulSets and direct peer-to-peer service discovery."},
    {q:"Two pods need to communicate. Which address is most reliable?",options:["Pod IP (changes on restart)","<service-name>.<namespace>.svc.cluster.local","Node hostname","External IP"],answer:1,explanation:"Always use Service DNS names, not pod IPs which change on every restart.\nFull DNS: <service>.<namespace>.svc.cluster.local.\nWithin the same namespace: just <service-name>."},
    // ── Config & Security extra ──
    {q:"A pod tries to read a Secret as an env var and gets 'secret not found'. What do you check?",options:["RBAC","Is the Secret in the same namespace as the pod?","StorageClass","CNI"],answer:1,explanation:"Secrets are namespace-scoped.\nA pod in namespace A cannot access a Secret in namespace B.\nCheck: kubectl get secret <name> -n <pod-namespace>."},
    {q:"kubectl get pods returns 'Error from server (Forbidden)'. What is the fix?",options:["kubectl restart","Define a RoleBinding linking the User/ServiceAccount to a Role with get/list pods","Change namespace","Delete etcd"],answer:1,explanation:"Forbidden = RBAC doesn't permit the action.\nYou need: a Role with resources:[\"pods\"], verbs:[\"get\",\"list\"], and a RoleBinding linking it to the user/serviceaccount."},
    {q:"A ConfigMap has keys key1 and key2. A pod tries to load key3. What happens?",options:["Pod runs with empty env var","Pod fails to start - 'key not found' error","ConfigMap updates automatically","Namespace mismatch"],answer:1,explanation:"Using valueFrom.configMapKeyRef with a missing key prevents the pod from starting, showing an Event error.\nVerify the key name in the ConfigMap."},
    {q:"An imagePullSecret is missing. The pod pulls from a private registry. What status?",options:["CrashLoopBackOff","ImagePullBackOff - authentication fails against the registry","ContainerCreating","Evicted"],answer:1,explanation:"Without imagePullSecret, kubelet can't authenticate to the private registry.\nPod shows ImagePullBackOff.\nFix: kubectl create secret docker-registry + add imagePullSecrets to pod spec."},
    {q:"A pod tries to run as root but PodSecurity standard=restricted. What happens?",options:["Pod runs as root","Pod is rejected - restricted requires runAsNonRoot:true","PodSecurity is inactive","Warning only"],answer:1,explanation:"PodSecurity Admission at restricted level requires runAsNonRoot:true, drop ALL capabilities, etc.\nPods that don't comply are rejected in Enforce mode."},
    {q:"A default-deny-all NetworkPolicy is applied to a namespace. What happens to traffic?",options:["Nothing changes","All ingress and egress is blocked unless explicitly allowed","Only DNS is blocked","Only HTTP is blocked"],answer:1,explanation:"A NetworkPolicy with empty podSelector:{} blocks all traffic.\nExplicit NetworkPolicies must be created for allowed traffic.\nNote: DNS (UDP 53) is also blocked!"},
    {q:"What is the difference between Role and ClusterRole in RBAC?",options:["No difference","Role is namespace-scoped; ClusterRole applies to cluster-wide resources","ClusterRole uses more CPU","Role is only for master nodes"],answer:1,explanation:"Role: permissions in a specific namespace only.\nClusterRole: permissions for cluster-wide resources (Nodes, PVs, Namespaces) or any namespace via RoleBinding."},
    {q:"A Secret value is base64-encoded. What is a common encoding mistake?",options:["base64 is invalid in K8s","echo 'value' | base64 adds a trailing newline - use echo -n instead","Secret is double-encrypted","kubectl doesn't support base64"],answer:1,explanation:"echo 'value' | base64 appends a newline character.\nUse echo -n 'value' | base64 to avoid it.\nA Secret with a trailing newline causes the app to receive a value with an extra character."},
    {q:"A ServiceAccount's pod tries to read ConfigMaps but gets Forbidden. What is missing?",options:["Namespace","A Role with get/list ConfigMaps + RoleBinding to the ServiceAccount","ClusterRole","TLS cert"],answer:1,explanation:"RBAC permissions are granted to ServiceAccounts.\nYou need: a Role with resources:[\"configmaps\"], verbs:[\"get\",\"list\"], and a RoleBinding linking it to the pod's ServiceAccount."},
    {q:"A pod has securityContext.readOnlyRootFilesystem=true but writes to /tmp. What happens?",options:["Write succeeds","Write to /tmp fails unless /tmp is an emptyDir volume","Pod is rejected","Root filesystem is encrypted"],answer:1,explanation:"readOnlyRootFilesystem prevents writing anywhere in the container filesystem.\nFix: mount an emptyDir volume at /tmp to allow temporary writes without compromising security."},
    {q:"Are Kubernetes Secrets encrypted at rest by default?",options:["Yes, always encrypted in etcd","No - base64-encoded only; encryption requires EncryptionConfiguration","Secrets are not stored in etcd","Secrets are more secure than ConfigMaps"],answer:1,explanation:"By default, Secrets in etcd are base64-encoded, not encrypted.\nFor encryption at rest, configure EncryptionConfiguration on the API server.\nFor production: use Vault, AWS Secrets Manager, or External Secrets Operator."},
    // ── Storage extra ──
    {q:"A PVC is Pending. The StorageClass exists. What do you check?",options:["DNS","Is the provisioner running? Check PVC Events with kubectl describe pvc","RBAC","kubectl restart"],answer:1,explanation:"PVC Pending with StorageClass = provisioner failed to create a PV. kubectl describe pvc shows Events.\nCheck: provisioner pod running? Correct permissions? Disk quota?"},
    {q:"A PV has Reclaim Policy=Retain. The PVC is deleted. What happens to the PV?",options:["PV is automatically deleted","PV stays in Released state - data preserved but no new PVC can bind to it","PV is wiped","PV binds to the next PVC"],answer:1,explanation:"Retain: PV is not deleted or wiped.\nIt moves to Released.\nTo reuse: manually remove the claimRef.\nDelete policy: PV is deleted with the PVC.\nRecycle: deprecated."},
    {q:"A StorageClass doesn't exist. A PVC references it. What is the PVC status?",options:["PVC creates with default storage","PVC stays Pending with 'storageclass not found' event","PVC is deleted","PV is created"],answer:1,explanation:"If the StorageClass doesn't exist, the PVC stays Pending. kubectl describe pvc shows 'storageclass not found'.\nVerify the StorageClass name."},
    {q:"A pod gets Permission denied writing to a volume. Container UID is 1000. What do you check?",options:["DNS","securityContext.fsGroup - sets volume ownership to a GID","RBAC","StorageClass"],answer:1,explanation:"Pod securityContext.fsGroup sets the GID for files created in the volume.\nIf not set and the volume is owned by root, UID 1000 cannot write.\nSet fsGroup=1000 in the pod's securityContext."},
    {q:"A PVC has accessMode=ReadWriteOnce. Two pods try to mount it on different nodes. What happens?",options:["Both get access","The second pod stays Pending - RWO allows mount on only one node","DNS error","Eviction"],answer:1,explanation:"ReadWriteOnce: the volume can only be mounted ReadWrite on one node at a time.\nA second pod on a different node stays Pending.\nUse RWX (ReadWriteMany) for multi-node access."},
    {q:"How do you resize an existing PVC?",options:["You cannot resize a PVC","StorageClass needs allowVolumeExpansion:true, then patch PVC with a larger size","Delete and recreate","Reformat the volume"],answer:1,explanation:"To expand a PVC: (1) StorageClass.allowVolumeExpansion:true, (2) kubectl patch pvc with a larger size.\nOnline expansion is supported by most CSI drivers.\nShrinking is not supported."},
    {q:"A StatefulSet pod-0 is deleted and recreated. What happens to its PVC?",options:["PVC is deleted","PVC is retained - the new pod-0 attaches to the same PVC with the same data","A new PVC is created","Data is lost"],answer:1,explanation:"This is a core StatefulSet feature: PVCs are named deterministically and are never deleted when a pod is deleted.\nThe new pod reconnects to the same PVC with its data intact."},
    {q:"Dynamic provisioning is not working. kubectl describe pvc shows 'waiting for a volume to be created'. What is the cause?",options:["RBAC","Provisioner pod not running, wrong StorageClass provisioner, or quota reached","DNS","Ingress"],answer:1,explanation:"Dynamic provisioning requires: (1) StorageClass with a provisioner set, (2) Provisioner pod running, (3) RBAC for the provisioner, (4) cloud provider quota not exhausted."},
    {q:"A PV has capacity=10Gi. A PVC requests 5Gi. Will they bind?",options:["No - sizes must match exactly","Yes - a PV with larger capacity can satisfy a PVC with a smaller request","PVC receives 10Gi","PV shrinks to 5Gi"],answer:1,explanation:"K8s finds a PV that satisfies: matching accessMode, storageClass, and capacity >= requested.\nA 10Gi PV can satisfy a 5Gi PVC."},
    // ── Troubleshooting extra ──
    {q:"A node is NotReady. What is the first step?",options:["kubectl delete node","kubectl describe node + ssh to node + systemctl status kubelet","Delete all pods","Scale down"],answer:1,explanation:"NotReady usually means kubelet isn't reporting.\nCheck: (1) kubectl describe node for Conditions, (2) ssh to node, (3) systemctl status kubelet, (4) journalctl -u kubelet -n 50."},
    {q:"kubectl exec -it pod -- /bin/bash returns 'OCI runtime exec failed'. Why?",options:["RBAC blocked","bash is not in the image (distroless) - try /bin/sh","DNS","StorageClass"],answer:1,explanation:"Minimal images like distroless don't include bash.\nTry: /bin/sh.\nIf that also fails: kubectl debug -it pod --image=busybox to attach an ephemeral debug container."},
    {q:"A pod has restartCount=47. What does this indicate?",options:["Healthy pod","Pod is crashing repeatedly - check logs --previous","Pod is upgrading","Normal behavior"],answer:1,explanation:"A high restartCount means the pod crashes and is restarted repeatedly (CrashLoopBackOff).\nCheck: kubectl logs <pod> --previous to see the last crash reason."},
    {q:"etcd has high disk I/O. The cluster is slow. What is the impact?",options:["Only pods are affected","API server slows down - etcd is the backend for all K8s objects; high latency slows the whole control plane","DNS fails","Nodes stop reporting"],answer:1,explanation:"etcd is the K8s brain.\nEvery kubectl apply/get goes through API server → etcd.\nDisk latency slows the entire control plane.\nFix: use SSDs, reduce watch connections, run etcd defrag."},
    {q:"kubectl get pods returns 'the server is currently unable to handle the request'. What is the cause?",options:["Pod crashed","API server is rate-limiting or overloaded - too many requests","DNS","CNI"],answer:1,explanation:"The API server limits requests to prevent overload.\nCommon causes: too many controllers, kubectl watch loops, or CI/CD running kubectl every second.\nCheck kube-apiserver metrics."},
    {q:"The container runtime (containerd) is unresponsive on a node. What doesn't work?",options:["Only new pods","Container management is impossible - no exec, no new logs, no new pods","DNS only","Ingress only"],answer:1,explanation:"kubelet communicates with the runtime via CRI.\nWithout the runtime: no container start, no exec, no log streaming.\nExisting containers keep running in hardware but kubelet can't manage them."},
    {q:"CoreDNS pods have crashed. What is the symptom in the cluster?",options:["Nodes go NotReady","Internal DNS fails - pods can't resolve service names","kubectl stops working","Ingress fails"],answer:1,explanation:"CoreDNS provides service discovery.\nWithout it, pods can't resolve <service>.<namespace>.svc.cluster.local and applications fail to connect to other services."},
    {q:"A cluster upgrade fails midway. What is the safest rollback approach?",options:["kubectl rollback","Restore etcd from a snapshot taken before the upgrade","Downgrade kubelet","Delete the control plane"],answer:1,explanation:"The only reliable way to roll back a K8s cluster is to restore from an etcd snapshot.\nKubernetes does not support direct downgrades.\nAlways take an etcd snapshot before any upgrade."},
    {q:"kubectl top nodes returns 'Metrics API not available'. What is the cause?",options:["Old kubectl version","metrics-server is not installed or not running","RBAC","etcd"],answer:1,explanation:"kubectl top requires the Metrics Server (aggregated API).\nWithout it, v1beta1.metrics.k8s.io doesn't exist.\nFix: install metrics-server.\nCheck: kubectl get apiservice | grep metrics."},
    {q:"A pod exits with code 137. What does this mean?",options:["Success","OOMKilled - the kernel terminated the process due to memory limit exceeded","Segfault","Container runtime crashed"],answer:1,explanation:"Exit code 137 = 128 + SIGKILL (signal 9).\nIn a container context this usually means OOMKilled.\nCheck: kubectl describe pod for OOMKilled event, then increase limits.memory."},
    {q:"kubectl apply returns 'field is immutable'. What do you do?",options:["Add --force","Delete and recreate the resource - immutable fields cannot be changed in place","kubectl edit","Change namespace"],answer:1,explanation:"Some K8s fields are immutable after creation (e.g., spec.selector on Service/Deployment).\nTo change them you must: kubectl delete + kubectl apply with the new definition."},
    {q:"How do you verify all control plane components are healthy?",options:["kubectl get all","kubectl get componentstatuses and kubectl get --raw '/healthz'","docker ps","netstat"],answer:1,explanation:"kubectl get componentstatuses shows scheduler, controller-manager, etcd status.\nAlso check: kubectl get pods -n kube-system for all control plane pods.\nOn newer K8s: kubectl get --raw '/healthz?verbose'."},
    {q:"A pod has 2 containers. The first container crashes. What happens?",options:["Both containers restart","Only the crashed container restarts; the pod keeps running","The pod is deleted","Depends on restartPolicy - with Always only the crashed container restarts"],answer:3,explanation:"In a multi-container pod, each container is managed independently.\nA crashing container is restarted per the pod's restartPolicy (Always/OnFailure/Never).\nThe pod itself is not deleted and other containers keep running."},
    {q:"A Deployment rollout is paused (kubectl rollout pause). What happens to new kubectl apply changes?",options:["Changes are applied immediately","Changes are staged but not rolled out until kubectl rollout resume","Deployment is deleted","An error is returned"],answer:1,explanation:"A paused Deployment stages configuration changes but doesn't apply them to pods.\nThis lets you batch multiple changes.\nResume with: kubectl rollout resume deployment/<name>."},
    {q:"A pod spec sets terminationGracePeriodSeconds=0. What does this mean?",options:["Pod gets infinite time to stop","Pod is killed immediately with SIGKILL - no graceful shutdown","Pod never stops","Default 30 seconds is used"],answer:1,explanation:"terminationGracePeriodSeconds=0 means no grace period.\nThe container receives SIGKILL immediately without the usual SIGTERM + wait.\nUse for fast testing only; never in production."},
    {q:"You want to run a one-off task in Kubernetes. Which resource is most appropriate?",options:["Deployment","Job - designed for run-to-completion workloads","DaemonSet","StatefulSet"],answer:1,explanation:"A Job runs pods until a specified number of successful completions.\nFor one-off tasks use a Job.\nFor scheduled tasks use CronJob.\nDeployments are for long-running services."},
    {q:"A pod's liveness probe keeps failing. What does Kubernetes do?",options:["Nothing","Restarts the container repeatedly","Deletes the pod permanently","Drains the node"],answer:1,explanation:"When a liveness probe fails, kubelet kills the container and restarts it (per restartPolicy).\nThis is intended for detecting and recovering from deadlocks.\nIf restartCount keeps rising, investigate the root cause."},
    {q:"What is the role of kube-scheduler in Kubernetes?",options:["Stores cluster state","Assigns pods to nodes based on resource availability and constraints","Runs containers","Manages Service networking"],answer:1,explanation:"kube-scheduler watches for unscheduled pods and selects the best node based on: resource requests, affinity/anti-affinity rules, taints/tolerations, and other constraints.\nIt only decides - kubelet does the actual work."},
  ],
};
